_CELL_18_CODE = '# --- Visualization: LOCAL edge importance around explained node (k-hop / incident) ---\nimport re\nfrom matplotlib import colors as mcolors\nfrom matplotlib.collections import LineCollection\n\n# Reuse explained node from previous cells; fallback to first test node.\nif "node_internal" not in globals():\n    node_internal = int(test_nodes_internal[0])\n\n# -----------------------------\n# Local explanation options\n# -----------------------------\n# LOCAL_SCOPE:\n# - "incident": FO uses only edges incident to node_internal\n# - "khop": keep edges/transitions in LOCAL_HOPS neighborhood of node_internal\n# - "global": no locality filtering\nLOCAL_SCOPE = "incident"\nLOCAL_HOPS = 1\nLOCAL_STRICT = True   # used only when LOCAL_SCOPE == "khop"\n\n# HO-specific incident filter role:\n# - "any": target appears in x, m, or v of transition (x->m)->(m->v)\n# - "middle": target must be m\n# - "endpoints": target must be x or v\nHO_INCIDENT_ROLE = "any"\n\n# Keep False by default to avoid disconnected-looking HO edges.\nHO_INCIDENT_RELAX = False\nHO_INCIDENT_RELAX_HOPS = 2\nHO_MIN_LOCAL_CANDIDATES = 20\n\n# HO render mode:\n# - "path": draw two node-space segments (x->m and m->v) per transition (recommended)\n# - "token": draw transition between token centroids\nHO_RENDER_MODE = "path"\n\nEDGE_SCORE_MODE_LOCAL = (\n    EDGE_SCORE_MODE if "EDGE_SCORE_MODE" in globals()\n    else SCORE_MODE if "SCORE_MODE" in globals()\n    else "target_overlap"\n)\nEDGE_GRP_ONLY_LOCAL = False\n\nFO_TOPK_LOCAL = 20\nHO_TOPK_LOCAL = 14\nFO_ABS_THRESH_LOCAL = 0.0\nHO_ABS_THRESH_LOCAL = 0.0\n\n# 2D embedding coordinates\nemb2 = node_embedding_to_plot2d(node_emb, seed=int(globals().get("seed", 0)))\n\npred_label = int(clf.predict(C_full[node_internal][None, :])[0])\nw, _b = _weights_for_class(clf, pred_label)\n\n# Build active concept set (same layout-prefix logic as node map)\nactive_prefix = "g2__" if SPRING_LAYOUT_ON_G2 else "g__"\nactive_idx = []\nactive_names = []\nfor j, name in enumerate(concept_names):\n    name_str = str(name)\n    if USE_BOTH_LAYOUT_CONCEPTS:\n        if not name_str.startswith(active_prefix):\n            continue\n        name_body = name_str.split("__", 1)[1]\n    else:\n        name_body = name_str\n\n    if EDGE_GRP_ONLY_LOCAL and re.search(r"_grp(\\d+)$", name_body) is None:\n        continue\n\n    active_idx.append(j)\n    active_names.append(name_body)\n\nif len(active_idx) == 0:\n    raise RuntimeError("No active concepts selected for local edge map. Check prefix/mask settings.")\n\nactive_idx = np.asarray(active_idx, dtype=int)\nC_active = np.asarray(C_full[:, active_idx], dtype=np.float32)\nw_active = np.asarray(w[active_idx], dtype=np.float32)\n\nif EDGE_SCORE_MODE_LOCAL == "class_alignment":\n    w_eff = w_active\n    score_formula = "C[node] * w_class(target_pred)"\nelif EDGE_SCORE_MODE_LOCAL == "target_overlap":\n    w_eff = C_active[node_internal] * w_active\n    score_formula = "C[node] * (C[target] * w_class(target_pred))"\nelse:\n    raise ValueError(f"Unknown EDGE_SCORE_MODE_LOCAL={EDGE_SCORE_MODE_LOCAL}")\n\nname_to_local = {n: i for i, n in enumerate(active_names)}\n\ndef _idx(family: str, grp: int):\n    return name_to_local.get(f"{family}_grp{int(grp)}", None)\n\nnode_group = np.asarray(group_of, dtype=int)\nn_nodes = int(graphs.n_nodes)\ntarget = int(node_internal)\n\n# -------------------------------------------------------------\n# Edge scores (same definition as the global edge cell)\n# -------------------------------------------------------------\ng_src = np.asarray(graphs.g_edge_index[0], dtype=int)\ng_dst = np.asarray(graphs.g_edge_index[1], dtype=int)\nE1 = int(g_src.shape[0])\nfo_scores = np.zeros((E1,), dtype=np.float32)\n\nfor e, (u, v) in enumerate(zip(g_src.tolist(), g_dst.tolist())):\n    gu = int(node_group[u])\n    gv = int(node_group[v])\n    terms = []\n\n    j = _idx("direct_out", gv)\n    if j is not None:\n        terms.append(float(C_active[u, j] * w_eff[j]))\n\n    j = _idx("direct_in", gu)\n    if j is not None:\n        terms.append(float(C_active[v, j] * w_eff[j]))\n\n    fo_scores[e] = float(np.mean(terms)) if len(terms) > 0 else 0.0\n\n# Higher-order transitions\ntok = np.asarray(graphs.g2_node_ids, dtype=int)\ng2s = np.asarray(graphs.g2_edge_index[0], dtype=int)\ng2t = np.asarray(graphs.g2_edge_index[1], dtype=int)\nE2 = int(g2s.shape[0])\nho_scores = np.zeros((E2,), dtype=np.float32)\n\nfor e, (a, b) in enumerate(zip(g2s.tolist(), g2t.tolist())):\n    x, _m1 = tok[a]\n    m2, v = tok[b]\n\n    gx = int(node_group[x])\n    gm = int(node_group[m2])\n    gv = int(node_group[v])\n    terms = []\n\n    j = _idx("out2_end", gv)\n    if j is not None:\n        terms.append(float(C_active[x, j] * w_eff[j]))\n\n    j = _idx("out2_mid", gm)\n    if j is not None:\n        terms.append(float(C_active[x, j] * w_eff[j]))\n\n    j = _idx("in2_start", gx)\n    if j is not None:\n        terms.append(float(C_active[v, j] * w_eff[j]))\n\n    j = _idx("in2_mid", gm)\n    if j is not None:\n        terms.append(float(C_active[v, j] * w_eff[j]))\n\n    ho_scores[e] = float(np.mean(terms)) if len(terms) > 0 else 0.0\n\n# -------------------------------------------------------------\n# Local masks\n# -------------------------------------------------------------\n# Undirected adjacency for neighborhood construction.\nadj = [[] for _ in range(n_nodes)]\nfor u, v in zip(g_src.tolist(), g_dst.tolist()):\n    uu, vv = int(u), int(v)\n    adj[uu].append(vv)\n    adj[vv].append(uu)\n\n\ndef _build_khop_mask(hops: int) -> np.ndarray:\n    m = np.zeros((n_nodes,), dtype=bool)\n    frontier = {target}\n    m[target] = True\n    for _ in range(max(int(hops), 0)):\n        nxt = set()\n        for u in frontier:\n            for v in adj[u]:\n                if not m[v]:\n                    m[v] = True\n                    nxt.add(v)\n        frontier = nxt\n        if len(frontier) == 0:\n            break\n    return m\n\n# k-hop node mask (main) + optional relaxed HO mask\nkhop_mask = _build_khop_mask(LOCAL_HOPS)\nho_relax_mask = _build_khop_mask(HO_INCIDENT_RELAX_HOPS)\n\n# incident node mask = target + 1-hop neighbors\nincident_mask = np.zeros((n_nodes,), dtype=bool)\nincident_mask[target] = True\nfor v in adj[target]:\n    incident_mask[int(v)] = True\n\n# Transition endpoint nodes for HO masks\nif E2 > 0:\n    x_nodes = tok[g2s, 0]\n    m_nodes = tok[g2t, 0]\n    v_nodes = tok[g2t, 1]\nelse:\n    x_nodes = np.zeros((0,), dtype=int)\n    m_nodes = np.zeros((0,), dtype=int)\n    v_nodes = np.zeros((0,), dtype=int)\n\nho_scope_used = LOCAL_SCOPE\nif LOCAL_SCOPE == "incident":\n    fo_local_mask = (g_src == target) | (g_dst == target)\n\n    if HO_INCIDENT_ROLE == "any":\n        ho_local_mask = (x_nodes == target) | (m_nodes == target) | (v_nodes == target)\n    elif HO_INCIDENT_ROLE == "middle":\n        ho_local_mask = (m_nodes == target)\n    elif HO_INCIDENT_ROLE == "endpoints":\n        ho_local_mask = (x_nodes == target) | (v_nodes == target)\n    else:\n        raise ValueError(f"Unknown HO_INCIDENT_ROLE={HO_INCIDENT_ROLE}")\n\n    # Optional relax only for HO if incident scope too narrow.\n    if HO_INCIDENT_RELAX and int(ho_local_mask.sum()) < int(HO_MIN_LOCAL_CANDIDATES):\n        ho_local_mask = ho_relax_mask[x_nodes] | ho_relax_mask[m_nodes] | ho_relax_mask[v_nodes]\n        ho_scope_used = f"incident({HO_INCIDENT_ROLE})->khop({int(HO_INCIDENT_RELAX_HOPS)})"\n        vis_local_mask = incident_mask | ho_relax_mask\n    else:\n        ho_scope_used = f"incident({HO_INCIDENT_ROLE})"\n        vis_local_mask = incident_mask\n\nelif LOCAL_SCOPE == "khop":\n    if LOCAL_STRICT:\n        fo_local_mask = khop_mask[g_src] & khop_mask[g_dst]\n        ho_local_mask = khop_mask[x_nodes] & khop_mask[m_nodes] & khop_mask[v_nodes]\n    else:\n        fo_local_mask = khop_mask[g_src] | khop_mask[g_dst]\n        ho_local_mask = khop_mask[x_nodes] | khop_mask[m_nodes] | khop_mask[v_nodes]\n    vis_local_mask = khop_mask\n\nelif LOCAL_SCOPE == "global":\n    fo_local_mask = np.ones((E1,), dtype=bool)\n    ho_local_mask = np.ones((E2,), dtype=bool)\n    vis_local_mask = np.ones((n_nodes,), dtype=bool)\n\nelse:\n    raise ValueError(f"Unknown LOCAL_SCOPE={LOCAL_SCOPE}")\n\n# Geometry for plotting\ntok_xy = 0.5 * (emb2[tok[:, 0]] + emb2[tok[:, 1]])\nfo_segments = np.stack([emb2[g_src], emb2[g_dst]], axis=1) if E1 > 0 else np.zeros((0, 2, 2), dtype=np.float32)\n\n\ndef _select_local(scores: np.ndarray, local_mask_arr: np.ndarray, topk: int, abs_thresh: float) -> np.ndarray:\n    if scores.size == 0:\n        return np.zeros((0,), dtype=int)\n\n    thr = float(max(abs_thresh, 0.0))\n    idx = np.where(local_mask_arr & (np.abs(scores) >= thr))[0]\n    if idx.size == 0:\n        return np.zeros((0,), dtype=int)\n\n    if topk <= 0 or topk >= idx.size:\n        return idx\n\n    local_order = np.argsort(-np.abs(scores[idx]))[: int(topk)]\n    return idx[local_order]\n\n\ndef _robust_norm(scores: np.ndarray):\n    if scores.size == 0:\n        vmax = 1.0\n    else:\n        vmax = float(np.quantile(np.abs(scores), 0.95))\n        vmax = max(vmax, 1e-6)\n    return mcolors.TwoSlopeNorm(vmin=-vmax, vcenter=0.0, vmax=vmax), vmax\n\n\nfo_keep = _select_local(fo_scores, fo_local_mask, FO_TOPK_LOCAL, FO_ABS_THRESH_LOCAL)\nho_keep = _select_local(ho_scores, ho_local_mask, HO_TOPK_LOCAL, HO_ABS_THRESH_LOCAL)\n\nfo_draw_scores = fo_scores[fo_keep]\nfo_draw_segments = fo_segments[fo_keep] if fo_keep.size else fo_segments[:0]\n\n# HO segments: default render as path segments in node space for connectivity clarity.\nif HO_RENDER_MODE == "token":\n    ho_segments_all = np.stack([tok_xy[g2s], tok_xy[g2t]], axis=1) if E2 > 0 else np.zeros((0, 2, 2), dtype=np.float32)\n    ho_draw_scores = ho_scores[ho_keep]\n    ho_draw_segments = ho_segments_all[ho_keep] if ho_keep.size else ho_segments_all[:0]\nelse:\n    seg_list = []\n    seg_score_list = []\n    for e in ho_keep.tolist():\n        a = int(g2s[e])\n        b = int(g2t[e])\n        x, _ = tok[a]\n        m, v = tok[b]\n        s = float(ho_scores[e])\n        # Draw transition as x->m and m->v so incident locality is visually explicit.\n        seg_list.append(np.asarray([emb2[int(x)], emb2[int(m)]], dtype=np.float32))\n        seg_score_list.append(s)\n        seg_list.append(np.asarray([emb2[int(m)], emb2[int(v)]], dtype=np.float32))\n        seg_score_list.append(s)\n\n    if len(seg_list) > 0:\n        ho_draw_segments = np.stack(seg_list, axis=0)\n        ho_draw_scores = np.asarray(seg_score_list, dtype=np.float32)\n    else:\n        ho_draw_segments = np.zeros((0, 2, 2), dtype=np.float32)\n        ho_draw_scores = np.zeros((0,), dtype=np.float32)\n\nfo_norm, fo_vmax = _robust_norm(fo_draw_scores)\nho_norm, ho_vmax = _robust_norm(ho_draw_scores)\n\nfig, (ax0, ax1) = plt.subplots(1, 2, figsize=(15, 6), constrained_layout=True)\n\n# --- Left: local FO edges ---\nax0.scatter(emb2[:, 0], emb2[:, 1], s=16, c="#d9d9d9", edgecolor="none", alpha=0.45)\nax0.scatter(emb2[vis_local_mask, 0], emb2[vis_local_mask, 1], s=26, c="#8f8f8f", edgecolor="none", alpha=0.8)\n\nif fo_draw_segments.shape[0] > 0:\n    lw0 = 0.7 + 3.0 * (np.abs(fo_draw_scores) / max(float(np.max(np.abs(fo_draw_scores))), 1e-8))\n    lc0 = LineCollection(\n        fo_draw_segments,\n        cmap="coolwarm",\n        norm=fo_norm,\n        linewidths=lw0,\n        alpha=0.95,\n    )\n    lc0.set_array(fo_draw_scores)\n    ax0.add_collection(lc0)\n    cb0 = fig.colorbar(lc0, ax=ax0)\n    cb0.set_label("local first-order edge importance")\n\nax0.scatter(\n    emb2[target, 0], emb2[target, 1],\n    marker="*", s=420, c="gold", edgecolor="black", linewidth=1.2, zorder=10,\n    label=f"explained node {target}",\n)\nax0.set_title(f"LOCAL FO importance ({LOCAL_SCOPE}) | shown={fo_draw_segments.shape[0]}")\nax0.set_xlabel("layout dim 1")\nax0.set_ylabel("layout dim 2")\nax0.legend(fontsize=8, frameon=False, loc="best")\n\n# --- Right: local HO transitions ---\nax1.scatter(emb2[:, 0], emb2[:, 1], s=16, c="#d9d9d9", edgecolor="none", alpha=0.45)\nax1.scatter(emb2[vis_local_mask, 0], emb2[vis_local_mask, 1], s=26, c="#8f8f8f", edgecolor="none", alpha=0.8)\n\nif ho_draw_segments.shape[0] > 0:\n    lw1 = 0.7 + 3.0 * (np.abs(ho_draw_scores) / max(float(np.max(np.abs(ho_draw_scores))), 1e-8))\n    lc1 = LineCollection(\n        ho_draw_segments,\n        cmap="coolwarm",\n        norm=ho_norm,\n        linewidths=lw1,\n        alpha=0.95,\n    )\n    lc1.set_array(ho_draw_scores)\n    ax1.add_collection(lc1)\n    cb1 = fig.colorbar(lc1, ax=ax1)\n    cb1.set_label("local higher-order transition importance")\n\nax1.scatter(\n    emb2[target, 0], emb2[target, 1],\n    marker="*", s=420, c="gold", edgecolor="black", linewidth=1.2, zorder=10,\n)\nax1.set_title(f"LOCAL HO importance ({ho_scope_used}, {HO_RENDER_MODE}) | shown={ho_draw_segments.shape[0]}")\nax1.set_xlabel("layout dim 1")\nax1.set_ylabel("layout dim 2")\n\nplt.show()\n\nprint(\n    f"Local settings: LOCAL_SCOPE={LOCAL_SCOPE} | LOCAL_HOPS={int(LOCAL_HOPS)} | LOCAL_STRICT={bool(LOCAL_STRICT)}"\n)\nprint(\n    f"HO local role={HO_INCIDENT_ROLE} | render={HO_RENDER_MODE} | "\n    f"relax={bool(HO_INCIDENT_RELAX)} (hops={int(HO_INCIDENT_RELAX_HOPS)}, min={int(HO_MIN_LOCAL_CANDIDATES)})"\n)\nprint(f"Edge score mode: {EDGE_SCORE_MODE_LOCAL} | formula: {score_formula}")\nprint(f"Local nodes highlighted: {int(vis_local_mask.sum())}/{n_nodes}")\nprint(\n    f"FO: local candidates={int(fo_local_mask.sum())}/{E1} | "\n    f"threshold={max(float(FO_ABS_THRESH_LOCAL),0.0):.6g} | shown={fo_draw_segments.shape[0]} | vmax={fo_vmax:.4f}"\n)\nprint(\n    f"HO: local candidates={int(ho_local_mask.sum())}/{E2} | "\n    f"threshold={max(float(HO_ABS_THRESH_LOCAL),0.0):.6g} | shown={ho_draw_segments.shape[0]} | vmax={ho_vmax:.4f}"\n)\n\nprint("\\nTop LOCAL FO edges by |importance|:")\nfo_order = np.argsort(-np.abs(fo_scores[fo_keep])) if fo_keep.size else np.zeros((0,), dtype=int)\nfor r, ii in enumerate(fo_order[: min(10, fo_keep.size)], start=1):\n    e = int(fo_keep[ii])\n    u, v = int(g_src[e]), int(g_dst[e])\n    print(f"  {r:2d}. ({u:3d}->{v:3d}) score={float(fo_scores[e]):+.4f}")\n\nprint("\\nTop LOCAL HO transitions by |importance|:")\nho_order = np.argsort(-np.abs(ho_scores[ho_keep])) if ho_keep.size else np.zeros((0,), dtype=int)\nfor r, ii in enumerate(ho_order[: min(10, ho_keep.size)], start=1):\n    e = int(ho_keep[ii])\n    a, b = int(g2s[e]), int(g2t[e])\n    u1, v1 = map(int, tok[a])\n    u2, v2 = map(int, tok[b])\n    print(f"  {r:2d}. ({u1:3d}->{v1:3d}) -> ({u2:3d}->{v2:3d}) score={float(ho_scores[e]):+.4f}")\n\n\n'

