_CELL_19_CODE = '# --- CBM explanation dashboard (2x2): local graph, concept waterfall, class heatmap, faithfulness ---\nimport re\nimport numpy as np\nimport matplotlib.pyplot as plt\nfrom matplotlib import colors as mcolors\nfrom matplotlib.collections import LineCollection\nfrom matplotlib.patches import FancyArrowPatch\nfrom matplotlib.cm import ScalarMappable\n\n# -----------------------------\n# Config\n# -----------------------------\nif "node_internal" not in globals():\n    node_internal = int(test_nodes_internal[0])\n\n# Scoring mode in concept space\nDASH_SCORE_MODE = SCORE_MODE if "SCORE_MODE" in globals() else "target_overlap"\nDASH_GROUP_ONLY = False\nDASH_LOCAL_ACTIVE_VIEW = LOCAL_ACTIVE_VIEW if "LOCAL_ACTIVE_VIEW" in globals() else "layout"\nDASH_FAITH_ACTIVE_VIEW = FAITH_ACTIVE_VIEW if "FAITH_ACTIVE_VIEW" in globals() else "all"\n\n# Local graph panel controls\nLOCAL_SCOPE_DASH = "incident"      # "incident" | "khop" | "global"\nLOCAL_HOPS_DASH = 1\nLOCAL_STRICT_DASH = True\nHO_INCIDENT_ROLE_DASH = "any"      # "any" | "middle" | "endpoints"\nFO_TOPK_DASH = 16\nHO_TOPK_DASH = 12\nFO_ABS_THRESH_DASH = 0.0\nHO_ABS_THRESH_DASH = 0.0\n\n# Waterfall / heatmap / faithfulness\nTOPK_POS_WATERFALL = 8\nTOPK_NEG_WATERFALL = 8\nHEATMAP_TOP_CONCEPTS = 20\nFAITH_MAX_K = 30\nFAITH_ORDER = "positive"      # "positive" | "abs" | "negative"\nFAITH_COMPARE_RANDOM = True\nFAITH_RANDOM_TRIALS = 40\nFAITH_RANDOM_SEED = 0\n\n# -----------------------------\n# Shared setup\n# -----------------------------\nemb2 = node_embedding_to_plot2d(node_emb, seed=int(globals().get("seed", 0)))\n\npred_label = int(clf.predict(C_full[node_internal][None, :])[0])\nw_pred_full, b_pred = _weights_for_class(clf, pred_label)\n\nactive_prefix = "g2__" if SPRING_LAYOUT_ON_G2 else "g__"\nactive_idx = []\nactive_names = []\nfor j, name in enumerate(concept_names):\n    name_str = str(name)\n    if USE_BOTH_LAYOUT_CONCEPTS:\n        if DASH_LOCAL_ACTIVE_VIEW == "layout" and (not name_str.startswith(active_prefix)):\n            continue\n        name_body = name_str.split("__", 1)[1] if "__" in name_str else name_str\n    else:\n        name_body = name_str\n\n    if DASH_GROUP_ONLY and re.search(r"_grp(\\d+)$", name_body) is None:\n        continue\n\n    active_idx.append(j)\n    active_names.append(name_body)\n\nif len(active_idx) == 0:\n    raise RuntimeError("No active concepts selected for dashboard.")\n\nactive_idx = np.asarray(active_idx, dtype=int)\nC_active = np.asarray(C_full[:, active_idx], dtype=np.float32)\nw_active_pred = np.asarray(w_pred_full[active_idx], dtype=np.float32)\n\n# Separate concept pool for faithfulness (can be broader than local-graph view).\nfaith_idx = select_active_indices(\n    concept_names,\n    use_both_layout_concepts=USE_BOTH_LAYOUT_CONCEPTS,\n    spring_layout_on_g2=SPRING_LAYOUT_ON_G2,\n    view=DASH_FAITH_ACTIVE_VIEW,\n)\nif faith_idx.size == 0:\n    faith_idx = active_idx.copy()\nC_faith = np.asarray(C_full[:, faith_idx], dtype=np.float32)\nw_faith_pred = np.asarray(w_pred_full[faith_idx], dtype=np.float32)\n\nif DASH_SCORE_MODE == "class_alignment":\n    w_eff = w_active_pred\n    score_formula = "C[i] * w_class(target_pred)"\nelif DASH_SCORE_MODE == "target_overlap":\n    w_eff = C_active[node_internal] * w_active_pred\n    score_formula = "C[i] * (C[target] * w_class(target_pred))"\nelse:\n    raise ValueError(f"Unknown DASH_SCORE_MODE={DASH_SCORE_MODE}")\n\nname_to_local = {n: i for i, n in enumerate(active_names)}\n\ndef _idx(family: str, grp: int):\n    return name_to_local.get(f"{family}_grp{int(grp)}", None)\n\ndef _family(name: str) -> str:\n    if "_grp" in name:\n        return name.split("_grp", 1)[0]\n    if name.endswith("_strength"):\n        return name[:-len("_strength")]\n    return name.split("_", 1)[0]\n\ndef _short(s: str, n: int = 28) -> str:\n    return s if len(s) <= n else s[: n - 3] + "..."\n\ndef _select_local(scores: np.ndarray, local_mask_arr: np.ndarray, topk: int, abs_thresh: float) -> np.ndarray:\n    if scores.size == 0:\n        return np.zeros((0,), dtype=int)\n    thr = float(max(abs_thresh, 0.0))\n    idx = np.where(local_mask_arr & (np.abs(scores) >= thr))[0]\n    if idx.size == 0:\n        return np.zeros((0,), dtype=int)\n    if topk <= 0 or topk >= idx.size:\n        return idx\n    local_order = np.argsort(-np.abs(scores[idx]))[: int(topk)]\n    return idx[local_order]\n\ndef _robust_norm(vals: np.ndarray):\n    if vals.size == 0:\n        vmax = 1.0\n    else:\n        vmax = float(np.quantile(np.abs(vals), 0.95))\n        vmax = max(vmax, 1e-6)\n    return mcolors.TwoSlopeNorm(vmin=-vmax, vcenter=0.0, vmax=vmax), vmax\n\n# -----------------------------\n# Compute FO / HO scores\n# -----------------------------\nnode_group = np.asarray(group_of, dtype=int)\n\ng_src = np.asarray(graphs.g_edge_index[0], dtype=int)\ng_dst = np.asarray(graphs.g_edge_index[1], dtype=int)\nE1 = int(g_src.shape[0])\nfo_scores = np.zeros((E1,), dtype=np.float32)\n\nfor e, (u, v) in enumerate(zip(g_src.tolist(), g_dst.tolist())):\n    gu = int(node_group[u])\n    gv = int(node_group[v])\n    terms = []\n    j = _idx("direct_out", gv)\n    if j is not None:\n        terms.append(float(C_active[u, j] * w_eff[j]))\n    j = _idx("direct_in", gu)\n    if j is not None:\n        terms.append(float(C_active[v, j] * w_eff[j]))\n    fo_scores[e] = float(np.mean(terms)) if terms else 0.0\n\n\ntok = np.asarray(graphs.g2_node_ids, dtype=int)\ng2s = np.asarray(graphs.g2_edge_index[0], dtype=int)\ng2t = np.asarray(graphs.g2_edge_index[1], dtype=int)\nE2 = int(g2s.shape[0])\nho_scores = np.zeros((E2,), dtype=np.float32)\n\nfor e, (a, b) in enumerate(zip(g2s.tolist(), g2t.tolist())):\n    x, _ = tok[a]\n    m, v = tok[b]\n    gx, gm, gv = int(node_group[x]), int(node_group[m]), int(node_group[v])\n    terms = []\n    j = _idx("out2_end", gv)\n    if j is not None:\n        terms.append(float(C_active[x, j] * w_eff[j]))\n    j = _idx("out2_mid", gm)\n    if j is not None:\n        terms.append(float(C_active[x, j] * w_eff[j]))\n    j = _idx("in2_start", gx)\n    if j is not None:\n        terms.append(float(C_active[v, j] * w_eff[j]))\n    j = _idx("in2_mid", gm)\n    if j is not None:\n        terms.append(float(C_active[v, j] * w_eff[j]))\n    ho_scores[e] = float(np.mean(terms)) if terms else 0.0\n\n# -----------------------------\n# Build locality masks\n# -----------------------------\nn_nodes = int(graphs.n_nodes)\ntarget = int(node_internal)\n\nadj = [[] for _ in range(n_nodes)]\nfor u, v in zip(g_src.tolist(), g_dst.tolist()):\n    uu, vv = int(u), int(v)\n    adj[uu].append(vv)\n    adj[vv].append(uu)\n\n\ndef _build_khop_mask(hops: int) -> np.ndarray:\n    m = np.zeros((n_nodes,), dtype=bool)\n    m[target] = True\n    frontier = {target}\n    for _ in range(max(int(hops), 0)):\n        nxt = set()\n        for u in frontier:\n            for v in adj[u]:\n                if not m[v]:\n                    m[v] = True\n                    nxt.add(v)\n        frontier = nxt\n        if not frontier:\n            break\n    return m\n\nkhop_mask = _build_khop_mask(LOCAL_HOPS_DASH)\nincident_mask = np.zeros((n_nodes,), dtype=bool)\nincident_mask[target] = True\nfor v in adj[target]:\n    incident_mask[int(v)] = True\n\nif E2 > 0:\n    x_nodes = tok[g2s, 0]\n    m_nodes = tok[g2t, 0]\n    v_nodes = tok[g2t, 1]\nelse:\n    x_nodes = np.zeros((0,), dtype=int)\n    m_nodes = np.zeros((0,), dtype=int)\n    v_nodes = np.zeros((0,), dtype=int)\n\nif LOCAL_SCOPE_DASH == "incident":\n    fo_local_mask = (g_src == target) | (g_dst == target)\n    if HO_INCIDENT_ROLE_DASH == "any":\n        ho_local_mask = (x_nodes == target) | (m_nodes == target) | (v_nodes == target)\n    elif HO_INCIDENT_ROLE_DASH == "middle":\n        ho_local_mask = (m_nodes == target)\n    elif HO_INCIDENT_ROLE_DASH == "endpoints":\n        ho_local_mask = (x_nodes == target) | (v_nodes == target)\n    else:\n        raise ValueError(f"Unknown HO_INCIDENT_ROLE_DASH={HO_INCIDENT_ROLE_DASH}")\n    vis_local_mask = incident_mask\n    ho_scope = f"incident({HO_INCIDENT_ROLE_DASH})"\nelif LOCAL_SCOPE_DASH == "khop":\n    if LOCAL_STRICT_DASH:\n        fo_local_mask = khop_mask[g_src] & khop_mask[g_dst]\n        ho_local_mask = khop_mask[x_nodes] & khop_mask[m_nodes] & khop_mask[v_nodes]\n    else:\n        fo_local_mask = khop_mask[g_src] | khop_mask[g_dst]\n        ho_local_mask = khop_mask[x_nodes] | khop_mask[m_nodes] | khop_mask[v_nodes]\n    vis_local_mask = khop_mask\n    ho_scope = f"khop({LOCAL_HOPS_DASH})"\nelif LOCAL_SCOPE_DASH == "global":\n    fo_local_mask = np.ones((E1,), dtype=bool)\n    ho_local_mask = np.ones((E2,), dtype=bool)\n    vis_local_mask = np.ones((n_nodes,), dtype=bool)\n    ho_scope = "global"\nelse:\n    raise ValueError(f"Unknown LOCAL_SCOPE_DASH={LOCAL_SCOPE_DASH}")\n\nfo_keep = _select_local(fo_scores, fo_local_mask, FO_TOPK_DASH, FO_ABS_THRESH_DASH)\nho_keep = _select_local(ho_scores, ho_local_mask, HO_TOPK_DASH, HO_ABS_THRESH_DASH)\n\nfo_draw_scores = fo_scores[fo_keep]\nho_draw_scores = ho_scores[ho_keep]\n\n# -----------------------------\n# Build 2x2 dashboard\n# -----------------------------\nfig, axs = plt.subplots(2, 2, figsize=(18, 12), constrained_layout=True)\nax_local, ax_water = axs[0, 0], axs[0, 1]\nax_heat, ax_faith = axs[1, 0], axs[1, 1]\n\n# =============================================================\n# Panel 1: Local graph (FO solid + HO dashed arrows)\n# =============================================================\nax_local.scatter(emb2[:, 0], emb2[:, 1], s=15, c="#d9d9d9", edgecolor="none", alpha=0.45)\nax_local.scatter(emb2[vis_local_mask, 0], emb2[vis_local_mask, 1], s=26, c="#8f8f8f", edgecolor="none", alpha=0.8)\n\n# Joint color scale across FO and HO in this panel.\njoint_vals = np.concatenate([fo_draw_scores, ho_draw_scores]) if (fo_draw_scores.size + ho_draw_scores.size) > 0 else np.zeros((1,), dtype=np.float32)\nnorm_local, _ = _robust_norm(joint_vals)\ncmap_local = plt.get_cmap("coolwarm")\n\n# FO: solid segments\nif fo_keep.size > 0:\n    fo_segments = np.stack([emb2[g_src[fo_keep]], emb2[g_dst[fo_keep]]], axis=1)\n    lw = 0.8 + 2.8 * (np.abs(fo_draw_scores) / max(float(np.max(np.abs(fo_draw_scores))), 1e-8))\n    lc = LineCollection(fo_segments, cmap=cmap_local, norm=norm_local, linewidths=lw, alpha=0.9)\n    lc.set_array(fo_draw_scores)\n    ax_local.add_collection(lc)\n\n# HO: dashed arrows on node-space paths x->m and m->v\nfor e in ho_keep.tolist():\n    a = int(g2s[e])\n    b = int(g2t[e])\n    x, _ = tok[a]\n    m, v = tok[b]\n    s = float(ho_scores[e])\n    col = cmap_local(norm_local(s))\n    absn = float(abs(s) / max(float(np.max(np.abs(ho_draw_scores))) if ho_draw_scores.size else 1.0, 1e-8))\n    width = 0.7 + 2.3 * absn\n    mscale = 8 + 4 * absn\n\n    arr1 = FancyArrowPatch(\n        posA=emb2[int(x)], posB=emb2[int(m)],\n        arrowstyle="-|>", mutation_scale=mscale,\n        linewidth=width, linestyle="--", color=col, alpha=0.9,\n        shrinkA=1.0, shrinkB=1.0,\n    )\n    arr2 = FancyArrowPatch(\n        posA=emb2[int(m)], posB=emb2[int(v)],\n        arrowstyle="-|>", mutation_scale=mscale,\n        linewidth=width, linestyle="--", color=col, alpha=0.9,\n        shrinkA=1.0, shrinkB=1.0,\n    )\n    ax_local.add_patch(arr1)\n    ax_local.add_patch(arr2)\n\nsm = ScalarMappable(norm=norm_local, cmap=cmap_local)\nsm.set_array([])\ncb0 = fig.colorbar(sm, ax=ax_local)\ncb0.set_label("Signed local edge/transition importance")\n\nax_local.scatter(\n    emb2[target, 0], emb2[target, 1],\n    marker="*", s=430, c="gold", edgecolor="black", linewidth=1.2, zorder=12,\n    label=f"explained node {target}",\n)\n\n# Auto-zoom around local evidence to avoid huge empty areas in node2vec PCA plots.\nfocus_nodes = {int(target)}\nif fo_keep.size > 0:\n    focus_nodes.update(np.asarray(g_src[fo_keep], dtype=int).tolist())\n    focus_nodes.update(np.asarray(g_dst[fo_keep], dtype=int).tolist())\nif ho_keep.size > 0:\n    focus_nodes.update(np.asarray(x_nodes[ho_keep], dtype=int).tolist())\n    focus_nodes.update(np.asarray(m_nodes[ho_keep], dtype=int).tolist())\n    focus_nodes.update(np.asarray(v_nodes[ho_keep], dtype=int).tolist())\nfocus_nodes = np.array(sorted(focus_nodes), dtype=int)\nif focus_nodes.size > 0:\n    xx = emb2[focus_nodes, 0]\n    yy = emb2[focus_nodes, 1]\n    xr = max(float(xx.max() - xx.min()), 1e-3)\n    yr = max(float(yy.max() - yy.min()), 1e-3)\n    mx = 0.55 * xr\n    my = 0.55 * yr\n    ax_local.set_xlim(float(xx.min() - mx), float(xx.max() + mx))\n    ax_local.set_ylim(float(yy.min() - my), float(yy.max() + my))\nax_local.set_title(\n    f"Local Graph: FO solid + HO dashed arrows | FO={fo_keep.size}, HO={ho_keep.size} ({ho_scope})"\n)\nax_local.set_xlabel("layout dim 1")\nax_local.set_ylabel("layout dim 2")\nax_local.legend(fontsize=8, frameon=False, loc="best")\n\n# =============================================================\n# Panel 2: Concept waterfall (top +/- w*x), grouped by family\n# =============================================================\nx_target = np.asarray(C_active[target], dtype=np.float32)\ncontrib_target = x_target * w_active_pred\n\npos_idx = np.where(contrib_target > 0)[0]\nneg_idx = np.where(contrib_target < 0)[0]\n\npos_top = pos_idx[np.argsort(-contrib_target[pos_idx])[: int(TOPK_POS_WATERFALL)]] if pos_idx.size else np.array([], dtype=int)\nneg_top = neg_idx[np.argsort(contrib_target[neg_idx])[: int(TOPK_NEG_WATERFALL)]] if neg_idx.size else np.array([], dtype=int)\nsel = np.concatenate([neg_top, pos_top]).astype(int)\n\nif sel.size > 0:\n    rows = []\n    for j in sel.tolist():\n        nm = active_names[j]\n        fam = _family(nm)\n        rows.append((fam, nm, float(contrib_target[j])))\n\n    # Group by family then by contribution.\n    rows = sorted(rows, key=lambda t: (t[0], t[2]))\n    fams = [r[0] for r in rows]\n    nms = [r[1] for r in rows]\n    vals = np.asarray([r[2] for r in rows], dtype=float)\n\n    fam_uniq = sorted(set(fams))\n    fam_palette = plt.get_cmap("tab10")\n    fam_color = {f: fam_palette(i % 10) for i, f in enumerate(fam_uniq)}\n\n    ys = np.arange(len(rows))\n    bar_colors = ["#2ca02c" if v > 0 else "#d62728" for v in vals]\n    edge_colors = [fam_color[f] for f in fams]\n\n    ax_water.barh(ys, vals, color=bar_colors, edgecolor=edge_colors, linewidth=1.8, alpha=0.9)\n    ax_water.axvline(0.0, color="black", linewidth=1.0)\n    ax_water.set_yticks(ys)\n    ax_water.set_yticklabels([f"{_short(nm)} [{fam}]" for nm, fam in zip(nms, fams)], fontsize=8)\n    ax_water.set_xlabel("Contribution (w * x) for predicted class")\n    ax_water.set_title("Top positive/negative concept impacts (grouped by family)")\n\n    # Family boundary separators.\n    for i in range(1, len(rows)):\n        if fams[i] != fams[i - 1]:\n            ax_water.axhline(i - 0.5, color="#888888", linestyle=":", linewidth=0.8)\nelse:\n    ax_water.text(0.5, 0.5, "No positive/negative concepts selected.", ha="center", va="center", transform=ax_water.transAxes)\n    ax_water.set_title("Top concept impacts")\n\n# =============================================================\n# Panel 3: Class signature heatmap (mean concept impact per predicted class)\n# =============================================================\nif "test_nodes_internal" in globals():\n    eval_nodes = np.asarray(test_nodes_internal, dtype=int)\nelse:\n    eval_nodes = np.where(np.asarray(labeled_mask, dtype=bool))[0]\n\nC_eval_full = np.asarray(C_full[eval_nodes], dtype=np.float32)\nC_eval_active = C_eval_full[:, active_idx]\npred_eval = np.asarray(clf.predict(C_eval_full), dtype=int)\nclasses = np.asarray(clf.classes_, dtype=int)\n\nsig = np.zeros((len(classes), C_eval_active.shape[1]), dtype=np.float32)\nfor r, c in enumerate(classes.tolist()):\n    w_c_full, _ = _weights_for_class(clf, int(c))\n    w_c_active = np.asarray(w_c_full[active_idx], dtype=np.float32)\n    m = pred_eval == int(c)\n    if np.any(m):\n        sig[r] = np.mean(C_eval_active[m] * w_c_active[None, :], axis=0)\n\nn_cols = int(min(int(HEATMAP_TOP_CONCEPTS), sig.shape[1]))\nif n_cols > 0:\n    col_score = np.max(np.abs(sig), axis=0)\n    top_cols = np.argsort(-col_score)[:n_cols]\n    sig_top = sig[:, top_cols]\n    names_top = [active_names[int(j)] for j in top_cols]\n\n    norm_hm, _ = _robust_norm(sig_top.reshape(-1))\n    im = ax_heat.imshow(sig_top, aspect="auto", cmap="coolwarm", norm=norm_hm)\n    ax_heat.set_title("Class signature heatmap (mean concept impact on eval split)")\n    ax_heat.set_yticks(np.arange(len(classes)))\n    ax_heat.set_yticklabels([f"class {int(c)}" for c in classes], fontsize=9)\n    ax_heat.set_xticks(np.arange(n_cols))\n    ax_heat.set_xticklabels([_short(n, 18) for n in names_top], rotation=75, ha="right", fontsize=8)\n    cb2 = fig.colorbar(im, ax=ax_heat)\n    cb2.set_label("mean w*x")\nelse:\n    ax_heat.text(0.5, 0.5, "No concepts to display.", ha="center", va="center", transform=ax_heat.transAxes)\n\n# =============================================================\n# Panel 4: Faithfulness curve (target node concept ablation)\n# =============================================================\n# Choose concept removal order.\ncontrib_target_faith = np.asarray(C_faith[target] * w_faith_pred, dtype=np.float32)\nif FAITH_ORDER == "positive":\n    pool = np.where(contrib_target_faith > 0)[0]\n    if pool.size > 0:\n        rank_local = pool[np.argsort(-contrib_target_faith[pool])]\n    else:\n        rank_local = np.argsort(-np.abs(contrib_target_faith))\nelif FAITH_ORDER == "negative":\n    pool = np.where(contrib_target_faith < 0)[0]\n    if pool.size > 0:\n        rank_local = pool[np.argsort(contrib_target_faith[pool])]  # most negative first\n    else:\n        rank_local = np.argsort(-np.abs(contrib_target_faith))\nelse:\n    rank_local = np.argsort(-np.abs(contrib_target_faith))\n\nk_max = int(min(int(FAITH_MAX_K), rank_local.size))\nk_vals = np.arange(k_max + 1, dtype=int)\n\nclasses_arr = np.asarray(clf.classes_, dtype=int)\npred_class_pos = int(np.where(classes_arr == pred_label)[0][0])\n\ndef _logits_vec(x_vec: np.ndarray) -> np.ndarray:\n    if hasattr(clf, "decision_function"):\n        d = np.asarray(clf.decision_function(x_vec[None, :])).reshape(-1)\n        if d.size == 1 and classes_arr.size == 2:\n            s = float(d[0])\n            return np.asarray([-s, s], dtype=float)\n        if d.size == classes_arr.size:\n            return d.astype(float)\n\n    # Fallback: log-probabilities as proxy logits.\n    if hasattr(clf, "predict_proba"):\n        p = np.asarray(clf.predict_proba(x_vec[None, :])[0], dtype=float)\n        return np.log(np.clip(p, 1e-12, 1.0))\n\n    # Last fallback: pred-class linear score + zeros for others.\n    z = np.zeros((classes_arr.size,), dtype=float)\n    z[pred_class_pos] = float(np.dot(x_vec, w_pred_full) + b_pred)\n    return z\n\ndef _eval_curve(order_local: np.ndarray):\n    probs = []\n    logits = []\n    margins = []\n    preds = []\n\n    for k in k_vals.tolist():\n        x_mod = np.asarray(C_full[target], dtype=np.float32).copy()\n        if k > 0 and order_local.size > 0:\n            drop_local = order_local[:k]\n            drop_global = faith_idx[drop_local]\n            x_mod[drop_global] = 0.0\n\n        if hasattr(clf, "predict_proba"):\n            p = np.asarray(clf.predict_proba(x_mod[None, :])[0], dtype=float)\n            p_pred = float(p[pred_class_pos])\n        else:\n            p_pred = np.nan\n\n        z = _logits_vec(x_mod)\n        z_pred = float(z[pred_class_pos])\n        z_other = np.delete(z, pred_class_pos)\n        margin = z_pred - (float(np.max(z_other)) if z_other.size > 0 else 0.0)\n\n        pred_k = int(clf.predict(x_mod[None, :])[0])\n\n        probs.append(p_pred)\n        logits.append(z_pred)\n        margins.append(margin)\n        preds.append(pred_k)\n\n    return (\n        np.asarray(probs, dtype=float),\n        np.asarray(logits, dtype=float),\n        np.asarray(margins, dtype=float),\n        np.asarray(preds, dtype=int),\n    )\n\nprob_curve, logit_curve, margin_curve, pred_curve = _eval_curve(rank_local)\nlogit_drop = logit_curve[0] - logit_curve\nmargin_drop = margin_curve[0] - margin_curve\n\n# Random baseline using the same pool size.\nrand_prob_mean = None\nrand_prob_std = None\nrand_margin_drop_mean = None\nrand_margin_drop_std = None\n\nif FAITH_COMPARE_RANDOM and rank_local.size > 0 and k_max > 0:\n    if FAITH_ORDER == "positive":\n        rand_pool = np.where(contrib_target > 0)[0]\n    elif FAITH_ORDER == "negative":\n        rand_pool = np.where(contrib_target < 0)[0]\n    else:\n        rand_pool = np.where(np.abs(contrib_target) > 0)[0]\n\n    if rand_pool.size < rank_local.size:\n        rand_pool = np.arange(contrib_target_faith.shape[0], dtype=int)\n\n    rng = np.random.default_rng(int(FAITH_RANDOM_SEED))\n    rand_probs = []\n    rand_margin_drops = []\n\n    for _ in range(int(max(1, FAITH_RANDOM_TRIALS))):\n        perm = rng.permutation(rand_pool)\n        order_rand = perm[: rank_local.size]\n        p_r, z_r, m_r, _ = _eval_curve(order_rand)\n        rand_probs.append(p_r)\n        rand_margin_drops.append(m_r[0] - m_r)\n\n    rand_probs = np.asarray(rand_probs, dtype=float)\n    rand_margin_drops = np.asarray(rand_margin_drops, dtype=float)\n\n    rand_prob_mean = np.nanmean(rand_probs, axis=0)\n    rand_prob_std = np.nanstd(rand_probs, axis=0)\n    rand_margin_drop_mean = np.nanmean(rand_margin_drops, axis=0)\n    rand_margin_drop_std = np.nanstd(rand_margin_drops, axis=0)\n\nax_faith.plot(k_vals, prob_curve, marker="o", color="tab:blue", label=f"P(class={pred_label}) top-{FAITH_ORDER}")\nif rand_prob_mean is not None:\n    ax_faith.plot(k_vals, rand_prob_mean, linestyle="--", color="tab:blue", alpha=0.7, label="P(class) random")\n    ax_faith.fill_between(\n        k_vals,\n        rand_prob_mean - rand_prob_std,\n        rand_prob_mean + rand_prob_std,\n        color="tab:blue",\n        alpha=0.12,\n        linewidth=0,\n    )\n\nax_faith.set_xlabel(f"k removed concepts ({FAITH_ORDER} ranking)")\nax_faith.set_ylabel("Predicted-class probability", color="tab:blue")\nax_faith.tick_params(axis="y", labelcolor="tab:blue")\nax_faith.set_title("Faithfulness curve (target node concept ablation)")\n\nax_faith2 = ax_faith.twinx()\nax_faith2.plot(k_vals, margin_drop, marker="s", linestyle="--", color="tab:red", label="Margin drop")\nif rand_margin_drop_mean is not None:\n    ax_faith2.plot(k_vals, rand_margin_drop_mean, linestyle=":", color="tab:red", alpha=0.7, label="Margin drop random")\n    ax_faith2.fill_between(\n        k_vals,\n        rand_margin_drop_mean - rand_margin_drop_std,\n        rand_margin_drop_mean + rand_margin_drop_std,\n        color="tab:red",\n        alpha=0.10,\n        linewidth=0,\n    )\nax_faith2.set_ylabel("Pred-class margin drop", color="tab:red")\nax_faith2.tick_params(axis="y", labelcolor="tab:red")\n\n# Mark first class flip, if any.\nflip_k = None\nfor k, pk in zip(k_vals.tolist(), pred_curve.tolist()):\n    if int(pk) != int(pred_label):\n        flip_k = int(k)\n        break\nif flip_k is not None:\n    y_top = np.nanmax(prob_curve) if np.isfinite(prob_curve).any() else 0.5\n    ax_faith.axvline(flip_k, color="black", linestyle=":", linewidth=1.2)\n    ax_faith.text(flip_k, y_top, f"flip@k={flip_k}", fontsize=8, ha="left", va="bottom")\n\n# Combined legend\nh1, l1 = ax_faith.get_legend_handles_labels()\nh2, l2 = ax_faith2.get_legend_handles_labels()\nax_faith.legend(h1 + h2, l1 + l2, fontsize=8, frameon=False, loc="best")\n\nplt.show()\n\nprint(f"Dashboard target node: {target} | true={int(y[target])} | pred={pred_label}")\nprint(f"Score mode: {DASH_SCORE_MODE} | formula: {score_formula}")\nprint(f"Concept view: local={DASH_LOCAL_ACTIVE_VIEW}, faith={DASH_FAITH_ACTIVE_VIEW}")\nprint(f"Local graph settings: scope={LOCAL_SCOPE_DASH}, ho_scope={ho_scope}, FO shown={fo_keep.size}, HO shown={ho_keep.size}")\nif rand_prob_mean is None:\n    print(f"Faithfulness: mode={FAITH_ORDER}, k_max={k_max}, flip_k={flip_k}, p0={prob_curve[0]:.4f}, p_end={prob_curve[-1]:.4f}")\nelse:\n    print(\n        f"Faithfulness: mode={FAITH_ORDER}, k_max={k_max}, flip_k={flip_k}, "\n        f"p_end={prob_curve[-1]:.4f} vs random={rand_prob_mean[-1]:.4f}, "\n        f"margin_drop_end={margin_drop[-1]:.4f} vs random={rand_margin_drop_mean[-1]:.4f}"\n    )\n\n\n\n'

