_CELL_20_CODE = '# --- Sanity check: concept ablation impact on one node (single or joint-duplicate groups) ---\nimport numpy as np\nimport pandas as pd\nimport matplotlib.pyplot as plt\n\nNODE = int(node_internal) if "node_internal" in globals() else int(test_nodes_internal[0])\nONLY_ACTIVE_VIEW = False   # True -> only g__ / g2__ active view if using both-layout concepts\nABLATE_TO = "zero"         # "zero" or "mean"\nSANITY_MODE = "joint_duplicates"  # "single" | "joint_duplicates"\n\nx0 = np.asarray(C_full[NODE], dtype=np.float32)\nclasses = np.asarray(clf.classes_, dtype=int)\n\ndef _logits_lr(clf, x):\n    if hasattr(clf, "decision_function"):\n        d = np.asarray(clf.decision_function(x[None, :])).reshape(-1)\n        if d.size == 1 and classes.size == 2:\n            return np.asarray([-d[0], d[0]], dtype=float)\n        if d.size == classes.size:\n            return d.astype(float)\n    p = np.asarray(clf.predict_proba(x[None, :])[0], dtype=float)\n    return np.log(np.clip(p, 1e-12, 1.0))\n\ndef _margin(z, pred_idx):\n    z_other = np.delete(z, pred_idx)\n    return float(z[pred_idx] - (np.max(z_other) if z_other.size else 0.0))\n\ndef _base_name(name: str) -> str:\n    s = str(name)\n    if "__" in s:\n        pref, rest = s.split("__", 1)\n        if pref in {"g", "g2"}:\n            return rest\n    return s\n\np0 = np.asarray(clf.predict_proba(x0[None, :])[0], dtype=float)\npred_idx = int(np.argmax(p0))\npred = int(classes[pred_idx])\nz0 = _logits_lr(clf, x0)\nm0 = _margin(z0, pred_idx)\n\nw_pred, _ = _weights_for_class(clf, pred)\n\nmask = np.ones(len(concept_names), dtype=bool)\nif ONLY_ACTIVE_VIEW and "USE_BOTH_LAYOUT_CONCEPTS" in globals() and USE_BOTH_LAYOUT_CONCEPTS:\n    pref = "g2__" if SPRING_LAYOUT_ON_G2 else "g__"\n    mask = np.array([str(n).startswith(pref) for n in concept_names], dtype=bool)\n\nmean_vec = np.asarray(C_full, dtype=np.float32).mean(axis=0)\n\n# Build ablation units\nunits = []\nif SANITY_MODE == "single":\n    for j in np.where(mask)[0].tolist():\n        nm = str(concept_names[j])\n        units.append((nm, [int(j)]))\nelse:\n    groups = {}\n    for j in np.where(mask)[0].tolist():\n        key = _base_name(str(concept_names[j]))\n        groups.setdefault(key, []).append(int(j))\n    # stable order by key for reproducibility\n    for key in sorted(groups.keys()):\n        units.append((key, groups[key]))\n\nrows = []\nfor unit_name, idxs in units:\n    x = x0.copy()\n    for j in idxs:\n        x[j] = 0.0 if ABLATE_TO == "zero" else float(mean_vec[j])\n\n    p = np.asarray(clf.predict_proba(x[None, :])[0], dtype=float)\n    z = _logits_lr(clf, x)\n    pred_new = int(classes[int(np.argmax(p))])\n\n    wx_vals = np.asarray([w_pred[j] * x0[j] for j in idxs], dtype=float)\n    rows.append({\n        "unit": str(unit_name),\n        "n_concepts": int(len(idxs)),\n        "members": " | ".join([str(concept_names[j]) for j in idxs]),\n        "sum_x_j": float(np.sum([x0[j] for j in idxs])),\n        "sum_w_j_pred": float(np.sum([w_pred[j] for j in idxs])),\n        "sum_w*x": float(np.sum(wx_vals)),\n        "max_abs_w*x": float(np.max(np.abs(wx_vals))) if wx_vals.size else 0.0,\n        "delta_p_pred": float(p0[pred_idx] - p[pred_idx]),      # >0 hurts predicted-class prob\n        "delta_margin": float(m0 - _margin(z, pred_idx)),       # >0 hurts predicted-class margin\n        "flip": int(pred_new != pred),\n    })\n\ndf = pd.DataFrame(rows).sort_values("delta_margin", ascending=False)\ndf_nonzero = df[(np.abs(df["delta_margin"]) > 1e-8) | (np.abs(df["sum_w*x"]) > 1e-8)].copy()\nprint(f"Non-zero units: {len(df_nonzero)}/{len(df)}")\n\nprint(\n    f"Node={NODE} | true={int(y[NODE])} | pred={pred} | mode={SANITY_MODE} | "\n    f"base P(pred)={p0[pred_idx]:.4f} | base margin={m0:.4f}"\n)\nprint("\\nTop units that hurt prediction most when ablated:")\ndisplay((df_nonzero if len(df_nonzero) > 0 else df).head(15)[["unit","n_concepts","sum_w*x","delta_p_pred","delta_margin","flip","members"]])\n\nprint("\\nUnits that help when ablated (contradictory features):")\ndisplay((df_nonzero if len(df_nonzero) > 0 else df).tail(10)[["unit","n_concepts","sum_w*x","delta_p_pred","delta_margin","flip","members"]])\n\nplt.figure(figsize=(5.5, 4.2))\nplt.scatter(df["sum_w*x"], df["delta_margin"], s=26, alpha=0.75)\nplt.axhline(0, color="k", lw=1)\nplt.axvline(0, color="k", lw=1)\nplt.xlabel("unit contribution sum(w*x)")\nplt.ylabel("delta margin after unit ablation")\nplt.title(f"Sanity ({SANITY_MODE}): contribution vs ablation effect")\nplt.tight_layout()\nplt.show()\n\n\n'

