_CELL_21_CODE = '# --- Human-readable explanation card (non-expert friendly) ---\nimport re\nimport numpy as np\nimport matplotlib.pyplot as plt\nfrom matplotlib.patches import FancyArrowPatch\nfrom pathlib import Path\n\nif "node_internal" not in globals():\n    node_internal = int(test_nodes_internal[0])\n\n# Save only the faithfulness curve (panel C) to figures/ by default.\nSAVE_EXPLANATION_CARD = bool(globals().get("save_explanation_card", True))\nSAVE_EXPLANATION_CARD_DPI = int(globals().get("save_explanation_card_dpi", 320))\nSAVE_EXPLANATION_CARD_DIR = str(globals().get("save_explanation_card_dir", "figures"))\n_DATASET_TAG = re.sub(r"[^A-Za-z0-9._-]+", "_", str(globals().get("dataset_key", "dataset"))).strip("_") or "dataset"\nSHOW_FAITH_CARD_NODE_IDS = bool(globals().get("show_faith_card_node_ids", False))\nSHOW_FAITH_CURVE_POINT_LABELS = bool(globals().get("show_faith_curve_point_labels", False))\nFAITH_CARD_TITLE_FONTSIZE = int(globals().get("faith_card_title_fontsize", 15))\nFAITH_CARD_AXIS_FONTSIZE = int(globals().get("faith_card_axis_fontsize", 13))\nFAITH_CARD_TICK_FONTSIZE = int(globals().get("faith_card_tick_fontsize", 11))\nFAITH_CARD_ANNOT_FONTSIZE = int(globals().get("faith_card_annot_fontsize", 10))\nFAITH_CARD_NODE_ID_FONTSIZE = int(globals().get("faith_card_node_id_fontsize", 12))\n\nemb2 = node_embedding_to_plot2d(node_emb, seed=int(globals().get("seed", 0)))\n\n\ndef pretty_concept_label(name: str) -> str:\n    s = str(name)\n    if "__" in s:\n        s = s.split("__", 1)[1]\n\n    fam_map = {\n        "direct_out": "sends interactions to",\n        "direct_in": "receives interactions from",\n        "in2_start": "receives 2-step paths from source group",\n        "in2_mid": "receives 2-step paths through middle group",\n        "out2_end": "starts 2-step paths ending in group",\n        "out2_mid": "starts 2-step paths through middle group",\n    }\n\n    m = re.match(r"(direct_out|direct_in|in2_start|in2_mid|out2_end|out2_mid)_grp(\\d+)$", s)\n    if m:\n        fam, grp = m.group(1), m.group(2)\n        return f"{fam_map[fam]} {grp}"\n\n    for fam in fam_map:\n        if s == f"{fam}_strength":\n            return f"overall {fam_map[fam].replace(\' to\', \'\').replace(\' from\', \'\')} volume"\n        if s == f"{fam}_entropy":\n            return f"diversity of {fam_map[fam]}"\n        if s == f"{fam}_top1_mass":\n            return f"focus on one dominant {fam_map[fam]}"\n        if s == f"{fam}_top_margin":\n            return f"dominance gap in {fam_map[fam]}"\n\n    motif_map = {\n        "fo_reciprocity_out_ratio": "reciprocal outgoing ties ratio",\n        "fo_reciprocity_in_ratio": "reciprocal incoming ties ratio",\n        "ho_return_out_ratio": "2-step paths returning to same node (out)",\n        "ho_return_in_ratio": "2-step paths returning to same node (in)",\n        "ho_bridge_out_ratio": "2-step bridge paths created (out)",\n        "ho_bridge_in_ratio": "2-step bridge paths received (in)",\n        "fo_out_minus_in_log_strength": "outgoing minus incoming interaction strength",\n    }\n    return motif_map.get(s, s)\n\n\nnode = int(node_internal)\nx_target = np.asarray(C_full[node], dtype=np.float32)\npred = int(clf.predict(x_target[None, :])[0])\nproba = np.asarray(clf.predict_proba(x_target[None, :])[0], dtype=float)\nclasses_arr = np.asarray(clf.classes_, dtype=int)\npred_pos = int(np.where(classes_arr == pred)[0][0])\np0 = float(proba[pred_pos])\n\nw_pred, _ = _weights_for_class(clf, pred)\ncontrib = np.asarray(x_target * w_pred, dtype=np.float32)\n\nnz = np.where(np.abs(contrib) > 1e-8)[0]\nif nz.size == 0:\n    raise RuntimeError("No non-zero concept contributions for this node.")\n\npos = nz[contrib[nz] > 0]\nneg = nz[contrib[nz] < 0]\n\npos_top = pos[np.argsort(-contrib[pos])[:6]] if pos.size else np.array([], dtype=int)\nneg_top = neg[np.argsort(contrib[neg])[:4]] if neg.size else np.array([], dtype=int)\nsel = np.concatenate([neg_top, pos_top]).astype(int)\nif sel.size == 0:\n    sel = nz[np.argsort(-np.abs(contrib[nz]))[:6]]\n\n# Individual concept interventions (recommended by CBM literature).\nrows = []\nfor j in sel.tolist():\n    x_mod = x_target.copy()\n    x_mod[j] = 0.0\n    p_mod = np.asarray(clf.predict_proba(x_mod[None, :])[0], dtype=float)\n    pred_mod = int(clf.predict(x_mod[None, :])[0])\n    rows.append({\n        "idx": int(j),\n        "name": str(concept_names[j]),\n        "label": pretty_concept_label(str(concept_names[j])),\n        "contrib": float(contrib[j]),\n        "delta_p": float(p0 - p_mod[pred_pos]),\n        "flip": int(pred_mod != pred),\n    })\n\nrows = sorted(rows, key=lambda r: abs(r["contrib"]), reverse=True)\n\n# Cumulative top-positive intervention curve.\npos_order = [r for r in rows if r["contrib"] > 0]\nif len(pos_order) == 0:\n    pos_order = rows[:]\n\nk_vals = np.arange(len(pos_order) + 1, dtype=int)\np_curve = []\nfor k in k_vals.tolist():\n    x_mod = x_target.copy()\n    if k > 0:\n        drop = [r["idx"] for r in pos_order[:k]]\n        x_mod[np.asarray(drop, dtype=int)] = 0.0\n    p_mod = np.asarray(clf.predict_proba(x_mod[None, :])[0], dtype=float)\n    p_curve.append(float(p_mod[pred_pos]))\np_curve = np.asarray(p_curve, dtype=float)\n\n# Local edge view: only incident edges with concept-based scores.\nsrc = np.asarray(graphs.g_edge_index[0], dtype=int)\ndst = np.asarray(graphs.g_edge_index[1], dtype=int)\nnode_group = np.asarray(group_of, dtype=int)\n\ndef _idxs_for_base(base: str):\n    out = []\n    for j, nm in enumerate(concept_names):\n        if str(nm).endswith(base):\n            out.append(j)\n    return out\n\ninc = np.where((src == node) | (dst == node))[0]\nedge_items = []\nfor e in inc.tolist():\n    u = int(src[e])\n    v = int(dst[e])\n    if u == node:\n        base = f"direct_out_grp{int(node_group[v])}"\n    else:\n        base = f"direct_in_grp{int(node_group[u])}"\n    idxs = _idxs_for_base(base)\n    s = float(np.sum(contrib[idxs])) if len(idxs) > 0 else 0.0\n    if abs(s) > 1e-10:\n        edge_items.append((u, v, s, base))\n\nedge_items = sorted(edge_items, key=lambda t: abs(t[2]), reverse=True)[:10]\nlocal_nodes = {node}\nfor u, v, *_ in edge_items:\n    local_nodes.add(int(u))\n    local_nodes.add(int(v))\nlocal_nodes = sorted(local_nodes)\n\nfig = plt.figure(figsize=(17, 8), constrained_layout=True)\ngs = fig.add_gridspec(2, 2, width_ratios=[1.25, 1.0], height_ratios=[1.0, 1.0])\nax_graph = fig.add_subplot(gs[:, 0])\nax_bar = fig.add_subplot(gs[0, 1])\nax_curve = fig.add_subplot(gs[1, 1])\n\n# Panel A: very local graph explanation.\nax_graph.scatter(emb2[:, 0], emb2[:, 1], s=14, c="#e5e5e5", edgecolor="none", alpha=0.45)\nax_graph.scatter(emb2[local_nodes, 0], emb2[local_nodes, 1], s=110, c="#9ecae1", edgecolor="white", linewidth=1.0, zorder=3)\n\nfor u, v, s, _ in edge_items:\n    col = "#D55E00" if s > 0 else "#0072B2"\n    width = 1.2 + 4.0 * (abs(s) / max(max(abs(t[2]) for t in edge_items), 1e-8))\n    arr = FancyArrowPatch(\n        posA=emb2[int(u)],\n        posB=emb2[int(v)],\n        arrowstyle=\'-|>\',\n        mutation_scale=11,\n        linewidth=width,\n        color=col,\n        alpha=0.9,\n        zorder=4,\n    )\n    ax_graph.add_patch(arr)\n\nif SHOW_FAITH_CARD_NODE_IDS:\n    for nid in local_nodes:\n        ax_graph.text(\n            emb2[nid, 0],\n            emb2[nid, 1],\n            str(int(nid)),\n            fontsize=FAITH_CARD_NODE_ID_FONTSIZE,\n            ha=\'center\',\n            va=\'center\',\n            zorder=5,\n        )\n\nax_graph.scatter(\n    emb2[node, 0], emb2[node, 1],\n    marker=\'*\', s=520, c=\'gold\', edgecolor=\'black\', linewidth=1.5, zorder=6,\n)\n\n# Auto-zoom around local evidence nodes for readability in node2vec PCA space.\n_focus = np.asarray(local_nodes, dtype=int)\nif _focus.size > 0:\n    _xx = emb2[_focus, 0]\n    _yy = emb2[_focus, 1]\n    _xr = max(float(_xx.max() - _xx.min()), 1e-3)\n    _yr = max(float(_yy.max() - _yy.min()), 1e-3)\n    _mx = 0.55 * _xr\n    _my = 0.55 * _yr\n    ax_graph.set_xlim(float(_xx.min() - _mx), float(_xx.max() + _mx))\n    ax_graph.set_ylim(float(_yy.min() - _my), float(_yy.max() + _my))\nax_graph.set_title(\n    \'Why this node? Local interaction evidence (orange supports, blue opposes)\',\n    fontsize=FAITH_CARD_TITLE_FONTSIZE,\n)\nax_graph.set_xlabel(\'layout dim 1\', fontsize=FAITH_CARD_AXIS_FONTSIZE)\nax_graph.set_ylabel(\'layout dim 2\', fontsize=FAITH_CARD_AXIS_FONTSIZE)\nax_graph.tick_params(axis=\'both\', labelsize=FAITH_CARD_TICK_FONTSIZE)\n\n# Panel B: concept contribution bars + intervention effect.\nlabels = [r[\'label\'] for r in rows]\nvals = np.asarray([r[\'contrib\'] for r in rows], dtype=float)\ndp = np.asarray([r[\'delta_p\'] for r in rows], dtype=float)\ncols = ["#D55E00" if v > 0 else "#0072B2" for v in vals]\n\nys = np.arange(len(rows))\nax_bar.barh(ys, vals, color=cols, alpha=0.9)\nax_bar.axvline(0.0, color=\'black\', linewidth=1)\nax_bar.set_yticks(ys)\nax_bar.set_yticklabels(labels, fontsize=FAITH_CARD_TICK_FONTSIZE)\nax_bar.set_xlabel(\'concept contribution (w*x)\', fontsize=FAITH_CARD_AXIS_FONTSIZE)\nax_bar.set_title(\'Top concepts for this prediction\', fontsize=FAITH_CARD_TITLE_FONTSIZE)\nax_bar.tick_params(axis=\'x\', labelsize=FAITH_CARD_TICK_FONTSIZE)\n\nfor y_i, d in zip(ys.tolist(), dp.tolist()):\n    ax_bar.text(\n        vals[y_i] + (0.02 if vals[y_i] >= 0 else -0.02),\n        y_i,\n        f"  Δp={d:+.2f}",\n        va=\'center\',\n        ha=\'left\' if vals[y_i] >= 0 else \'right\',\n        fontsize=FAITH_CARD_ANNOT_FONTSIZE,\n    )\n\n# Panel C: cumulative intervention on top supportive concepts.\nax_curve.plot(k_vals, p_curve, marker=\'o\', color=\'#D55E00\', linewidth=2.2)\nax_curve.set_xticks(k_vals)\nax_curve.set_xlabel(\'k top supportive concepts removed\', fontsize=FAITH_CARD_AXIS_FONTSIZE)\nax_curve.set_ylabel(f\'P(class={pred})\', fontsize=FAITH_CARD_AXIS_FONTSIZE)\nax_curve.set_title(\'Counterfactual check: remove strongest concepts\', fontsize=FAITH_CARD_TITLE_FONTSIZE)\nax_curve.grid(alpha=0.25)\nax_curve.tick_params(axis=\'both\', labelsize=FAITH_CARD_TICK_FONTSIZE)\n\nif SHOW_FAITH_CURVE_POINT_LABELS:\n    for k, p in zip(k_vals.tolist(), p_curve.tolist()):\n        ax_curve.text(k, p, f"{p:.2f}", fontsize=FAITH_CARD_ANNOT_FONTSIZE, ha=\'center\', va=\'bottom\')\n\nsaved_path = None\nif SAVE_EXPLANATION_CARD:\n    out_dir = Path(SAVE_EXPLANATION_CARD_DIR)\n    out_dir.mkdir(parents=True, exist_ok=True)\n    base = str(\n        globals().get(\n            "save_explanation_card_basename",\n            f"{_DATASET_TAG}_faithfulness_curve_node{node}_pred{pred}",\n        )\n    )\n    safe_base = re.sub(r"[^A-Za-z0-9._-]+", "_", base).strip("_")\n    if len(safe_base) == 0:\n        safe_base = f"{_DATASET_TAG}_faithfulness_curve_node{node}"\n    if not safe_base.startswith(f"{_DATASET_TAG}_"):\n        safe_base = f"{_DATASET_TAG}_{safe_base}"\n    saved_path = out_dir / f"{safe_base}.pdf"\n\n    # Export only panel C as a standalone figure for thesis use.\n    fig_curve, ax_curve_save = plt.subplots(figsize=(7.2, 4.6), constrained_layout=True)\n    ax_curve_save.plot(k_vals, p_curve, marker=\'o\', color=\'#D55E00\', linewidth=2.2)\n    ax_curve_save.set_xticks(k_vals)\n    ax_curve_save.set_xlabel(\'k top supportive concepts removed\', fontsize=FAITH_CARD_AXIS_FONTSIZE)\n    ax_curve_save.set_ylabel(f\'P(class={pred})\', fontsize=FAITH_CARD_AXIS_FONTSIZE)\n    ax_curve_save.set_title(\'Counterfactual check: remove strongest concepts\', fontsize=FAITH_CARD_TITLE_FONTSIZE)\n    ax_curve_save.grid(alpha=0.25)\n    ax_curve_save.tick_params(axis=\'both\', labelsize=FAITH_CARD_TICK_FONTSIZE)\n    if SHOW_FAITH_CURVE_POINT_LABELS:\n        for k, p in zip(k_vals.tolist(), p_curve.tolist()):\n            ax_curve_save.text(k, p, f"{p:.2f}", fontsize=FAITH_CARD_ANNOT_FONTSIZE, ha=\'center\', va=\'bottom\')\n    fig_curve.savefig(saved_path, dpi=SAVE_EXPLANATION_CARD_DPI, bbox_inches="tight")\n    plt.close(fig_curve)\n\nplt.show()\nif saved_path is not None:\n    print(f"[saved figure] {saved_path}")\n\nprint(f"Node {node} predicted class {pred} (probability={p0:.3f}).")\nprint("Main reasons (highest positive concept contributions):")\nfor r in [x for x in rows if x[\'contrib\'] > 0][:4]:\n    flip_txt = " | flips class when removed" if r[\'flip\'] else ""\n    print(f"  - {r[\'label\']}: contribution={r[\'contrib\']:+.3f}, Δp={r[\'delta_p\']:+.3f}{flip_txt}")\n\nif any(r[\'contrib\'] < 0 for r in rows):\n    print("Concepts that push against this class:")\n    for r in [x for x in rows if x[\'contrib\'] < 0][:3]:\n        print(f"  - {r[\'label\']}: contribution={r[\'contrib\']:+.3f}")\n'

