_CELL_23_CODE = '# --- Adaptive concept maps (PDF-friendly compact version: less text, bigger fonts) ---\nimport re\nimport math\nfrom pathlib import Path\nimport numpy as np\nimport matplotlib.pyplot as plt\nfrom matplotlib.patches import FancyArrowPatch\n\nif "node_internal" not in globals():\n    node_internal = int(test_nodes_internal[0])\nnode = int(node_internal)\nif "emb2" not in globals():\n    emb2 = node_embedding_to_plot2d(node_emb, seed=int(globals().get("seed", 0)))\n\nnames = [str(n) for n in concept_names]\npred_label = int(clf.predict(C_full[node][None, :])[0])\npred_prob = float(clf.predict_proba(C_full[node][None, :])[0, pred_label])\nw_pred, _ = _weights_for_class(clf, pred_label)\ncontrib_full = np.asarray(C_full[node] * w_pred, dtype=float)\n\n# ------------------------------------------------------------\n# Compact PDF controls\n# ------------------------------------------------------------\nPDF_TOP_POS = int(globals().get("pdf_panels_top_pos", 4))\nPDF_TOP_NEG = int(globals().get("pdf_panels_top_neg", 2))\nPDF_MAX_PANELS = int(globals().get("pdf_panels_max", 6))\nPDF_COLS = int(globals().get("pdf_panels_cols", 2))\nPDF_SHOW_NODE_IDS = bool(globals().get("pdf_panels_show_node_ids", False))\nPDF_INCLUDE_NEGATIVE = bool(globals().get("pdf_panels_include_negative", False))\nPDF_REUSE_SELECTED_ROWS = bool(globals().get("pdf_panels_reuse_selected_rows", False))\n\nPDF_FONTSIZE_TITLE = int(globals().get("pdf_panels_title_fontsize", 17))\nPDF_FONTSIZE_META = int(globals().get("pdf_panels_meta_fontsize", 14))\nPDF_FONTSIZE_SUPTITLE = int(globals().get("pdf_panels_suptitle_fontsize", 20))\nPDF_FONTSIZE_NODE_IDS = int(globals().get("pdf_panels_node_id_fontsize", 11))\nPDF_DPI = int(globals().get("pdf_panels_dpi", 320))\n\nSAVE_ADAPTIVE_PANELS_COMPACT = bool(globals().get("save_adaptive_panels_compact", True))\nSAVE_ADAPTIVE_PANELS_COMPACT_PDF = bool(globals().get("save_adaptive_panels_compact_pdf", True))\nSAVE_ADAPTIVE_PANELS_COMPACT_PNG = bool(globals().get("save_adaptive_panels_compact_png", False))\nSAVE_ADAPTIVE_PANELS_COMPACT_DIR = str(globals().get("save_adaptive_panels_compact_dir", "figures"))\n_DATASET_TAG = re.sub(r"[^A-Za-z0-9._-]+", "_", str(globals().get("dataset_key", "dataset"))).strip("_") or "dataset"\nSAVE_ADAPTIVE_PANELS_COMPACT_BASENAME = str(\n    globals().get("save_adaptive_panels_compact_basename", f"{_DATASET_TAG}_adaptive_panels_compact_node{node}_pred{pred_label}")\n)\n\nTOP_FO = int(globals().get("pdf_panels_top_fo", 10))\nTOP_HO = int(globals().get("pdf_panels_top_ho", 10))\n\nsrc = np.asarray(graphs.g_edge_index[0], dtype=int)\ndst = np.asarray(graphs.g_edge_index[1], dtype=int)\nedge_w = np.asarray(graphs.g_edge_weight, dtype=float).reshape(-1)\nif edge_w.shape[0] != src.shape[0]:\n    edge_w = np.ones((src.shape[0],), dtype=float)\n\ntok = np.asarray(graphs.g2_node_ids, dtype=int)\ng2s = np.asarray(graphs.g2_edge_index[0], dtype=int)\ng2t = np.asarray(graphs.g2_edge_index[1], dtype=int)\ng2w = np.asarray(graphs.g2_edge_weight, dtype=float).reshape(-1)\nif g2w.shape[0] != g2s.shape[0]:\n    g2w = np.ones((g2s.shape[0],), dtype=float)\n\ng2_x = tok[g2s, 0] if g2s.size else np.zeros((0,), dtype=int)\ng2_m = tok[g2t, 0] if g2t.size else np.zeros((0,), dtype=int)\ng2_v = tok[g2t, 1] if g2t.size else np.zeros((0,), dtype=int)\n\nfallback_direct_in_strength = np.bincount(dst, weights=edge_w, minlength=int(graphs.n_nodes)).astype(float)\nfallback_direct_out_strength = np.bincount(src, weights=edge_w, minlength=int(graphs.n_nodes)).astype(float)\nfallback_in2_strength = np.bincount(g2_v, weights=g2w, minlength=int(graphs.n_nodes)).astype(float) if g2_v.size else np.zeros((graphs.n_nodes,), dtype=float)\nfallback_out2_strength = np.bincount(g2_x, weights=g2w, minlength=int(graphs.n_nodes)).astype(float) if g2_x.size else np.zeros((graphs.n_nodes,), dtype=float)\n\n\ndef _split_name(name: str):\n    s = str(name)\n    if "__" in s:\n        pref, body = s.split("__", 1)\n    else:\n        pref, body = "active", s\n    return pref, body\n\n\ndef _base_name(name: str):\n    return _split_name(name)[1]\n\n\ndef _group_array_for_prefix(prefix: str):\n    if prefix == "g" and "group_of_g" in globals():\n        return np.asarray(group_of_g, dtype=int)\n    if prefix == "g2" and "group_of_g2" in globals():\n        return np.asarray(group_of_g2, dtype=int)\n    return np.asarray(group_of, dtype=int)\n\n\ndef _norm01(x: np.ndarray):\n    x = np.asarray(x, dtype=float)\n    if x.size == 0:\n        return x\n    mn = float(np.min(x))\n    mx = float(np.max(x))\n    return (x - mn) / max(mx - mn, 1e-12)\n\n\ndef _draw_arrow(ax, p0, p1, color, lw=2.0, alpha=0.9, linestyle="-", rad=0.0):\n    if np.allclose(p0, p1):\n        return\n    arr = FancyArrowPatch(\n        posA=p0,\n        posB=p1,\n        arrowstyle="-|>",\n        mutation_scale=12,\n        linewidth=lw,\n        linestyle=linestyle,\n        color=color,\n        alpha=alpha,\n        zorder=7,\n        connectionstyle=f"arc3,rad={float(rad):.3f}",\n    )\n    ax.add_patch(arr)\n\n\ndef _parse_family_group(base: str):\n    m = re.match(r"^(direct_out|direct_in|in2_mid|in2_start|out2_mid|out2_end)_grp(\\d+)$", base)\n    if m is None:\n        return None\n    return m.group(1), int(m.group(2))\n\n\ndef _parse_family_agg(base: str):\n    m = re.match(r"^(direct_out|direct_in|in2_mid|in2_start|out2_mid|out2_end)_(strength|top1_mass|top_margin|entropy)$", base)\n    if m is None:\n        return None\n    return m.group(1), m.group(2)\n\n\ndef _parse_motif(base: str):\n    motifs = {\n        "fo_reciprocity_out_ratio",\n        "fo_reciprocity_in_ratio",\n        "ho_return_out_ratio",\n        "ho_return_in_ratio",\n        "ho_bridge_out_ratio",\n        "ho_bridge_in_ratio",\n        "fo_out_minus_in_log_strength",\n    }\n    return base if base in motifs else None\n\n\ndef _map_from_name(name: str, mode: str = "mean", fallback_vals=None):\n    idx = [j for j, nm in enumerate(names) if str(nm) == str(name)]\n    if len(idx) == 0:\n        base = _base_name(name)\n        idx = [j for j, nm in enumerate(names) if _base_name(nm) == base]\n\n    if len(idx) > 0:\n        arr = np.asarray(C_full[:, idx], dtype=float)\n        if mode == "sum":\n            return arr.sum(axis=1)\n        return arr.mean(axis=1)\n\n    if fallback_vals is not None:\n        return np.asarray(fallback_vals, dtype=float)\n    return np.zeros((C_full.shape[0],), dtype=float)\n\n\ndef _concept_label(name: str):\n    if "pretty_concept_label" in globals():\n        try:\n            return str(pretty_concept_label(name))\n        except Exception:\n            pass\n    return _base_name(name)\n\n\ndef _format_dp(val):\n    try:\n        x = float(val)\n    except Exception:\n        return "n/a"\n    return f"{x:+.2f}" if np.isfinite(x) else "n/a"\n\n\ndef _build_rows_from_contrib():\n    x_target = np.asarray(C_full[node], dtype=np.float32)\n    proba = np.asarray(clf.predict_proba(x_target[None, :])[0], dtype=float)\n    classes_arr = np.asarray(clf.classes_, dtype=int)\n    pred_pos = int(np.where(classes_arr == pred_label)[0][0])\n    p0 = float(proba[pred_pos])\n\n    nz = np.where(np.abs(contrib_full) > 1e-8)[0]\n    if nz.size == 0:\n        return []\n\n    top_idx = nz[np.argsort(-np.abs(contrib_full[nz]))[:12]]\n    out = []\n    for j in top_idx.tolist():\n        x_mod = x_target.copy()\n        x_mod[int(j)] = 0.0\n        p_mod = np.asarray(clf.predict_proba(x_mod[None, :])[0], dtype=float)\n        pred_mod = int(clf.predict(x_mod[None, :])[0])\n        out.append(\n            {\n                "idx": int(j),\n                "name": str(concept_names[j]),\n                "label": _concept_label(str(concept_names[j])),\n                "contrib": float(contrib_full[j]),\n                "delta_p": float(p0 - p_mod[pred_pos]),\n                "flip": int(pred_mod != pred_label),\n            }\n        )\n    return out\n\n\ndef _select_rows():\n    if PDF_REUSE_SELECTED_ROWS and "selected_rows" in globals() and isinstance(selected_rows, list) and len(selected_rows) > 0:\n        cand = [dict(r) for r in selected_rows]\n    else:\n        cand = _build_rows_from_contrib()\n\n    for r in cand:\n        if "name" not in r and "idx" in r:\n            r["name"] = str(concept_names[int(r["idx"])])\n        if "label" not in r:\n            r["label"] = _concept_label(str(r.get("name", "")))\n        if "contrib" not in r and "idx" in r:\n            r["contrib"] = float(contrib_full[int(r["idx"])])\n\n    cand = [r for r in cand if np.isfinite(float(r.get("contrib", np.nan)))]\n    if len(cand) == 0:\n        return []\n\n    pos = sorted([r for r in cand if float(r["contrib"]) > 0.0], key=lambda r: float(r["contrib"]), reverse=True)\n    neg = sorted([r for r in cand if float(r["contrib"]) < 0.0], key=lambda r: float(r["contrib"]))\n\n    selected = pos[: int(PDF_TOP_POS)]\n    if PDF_INCLUDE_NEGATIVE and int(PDF_TOP_NEG) > 0:\n        selected = selected + neg[: int(PDF_TOP_NEG)]\n    if len(selected) == 0:\n        selected = pos[: int(PDF_MAX_PANELS)]\n\n    seen = set()\n    out = []\n    for r in selected:\n        key = str(r.get("name", ""))\n        if key in seen:\n            continue\n        seen.add(key)\n        out.append(r)\n    return out[: int(PDF_MAX_PANELS)]\n\n\ndef _base_panel(ax):\n    ax.scatter(emb2[:, 0], emb2[:, 1], s=16, c="#d9d9d9", edgecolor="none", alpha=0.35, zorder=1)\n    ax.scatter(emb2[node, 0], emb2[node, 1], marker="*", s=420, c="gold", edgecolor="black", linewidth=1.4, zorder=10)\n    ax.set_xticks([])\n    ax.set_yticks([])\n\n\ndef _panel_title(ax, row: dict):\n    pref, _ = _split_name(str(row.get("name", "")))\n    ax.set_title(f"{row.get(\'label\', \'concept\')} [{pref}]", fontsize=PDF_FONTSIZE_TITLE)\n\n\ndef _panel_meta(ax, row: dict):\n    dp_txt = _format_dp(row.get("delta_p", np.nan))\n    flip_txt = "yes" if int(row.get("flip", 0)) else "no"\n    meta = f"dP={dp_txt} | flip={flip_txt}"\n    ax.text(\n        0.02,\n        0.98,\n        meta,\n        transform=ax.transAxes,\n        va="top",\n        ha="left",\n        fontsize=PDF_FONTSIZE_META,\n        bbox=dict(facecolor="white", alpha=0.82, edgecolor="none"),\n    )\n\n\ndef _draw_family_group_panel(ax, row: dict, family: str, k: int):\n    _base_panel(ax)\n    _panel_title(ax, row)\n\n    prefix = _split_name(row.get("name", "active"))[0]\n    group_arr = _group_array_for_prefix(prefix)\n\n    sign = 1.0 if float(row.get("contrib", 0.0)) >= 0.0 else -1.0\n    edge_col = "#d94801" if sign >= 0 else "#2171b5"\n    node_col = "#fdae6b" if sign >= 0 else "#9ecae1"\n\n    if family == "direct_out":\n        cand = np.where((src == node) & (group_arr[dst] == int(k)))[0]\n        if cand.size == 0:\n            _panel_meta(ax, row)\n            return\n        keep = cand[np.argsort(-edge_w[cand])[: int(min(TOP_FO, cand.size))]]\n        neigh = np.unique(dst[keep]).astype(int)\n        nstrength = np.bincount(dst[keep], weights=edge_w[keep], minlength=int(graphs.n_nodes))\n        nsize = 90 + 230 * _norm01(nstrength[neigh])\n        ax.scatter(emb2[neigh, 0], emb2[neigh, 1], s=nsize, c=node_col, edgecolor="white", linewidth=0.5, alpha=0.95, zorder=4)\n        wn = _norm01(edge_w[keep])\n        for e, nn in zip(keep.tolist(), wn.tolist()):\n            _draw_arrow(ax, emb2[int(src[e])], emb2[int(dst[e])], color=edge_col, lw=1.5 + 3.4 * nn)\n        if PDF_SHOW_NODE_IDS:\n            for n in neigh[:8]:\n                ax.text(\n                    float(emb2[n, 0]),\n                    float(emb2[n, 1]),\n                    str(int(n)),\n                    fontsize=PDF_FONTSIZE_NODE_IDS,\n                    ha="center",\n                    va="center",\n                    zorder=9,\n                )\n        _panel_meta(ax, row)\n        return\n\n    if family == "direct_in":\n        cand = np.where((dst == node) & (group_arr[src] == int(k)))[0]\n        if cand.size == 0:\n            _panel_meta(ax, row)\n            return\n        keep = cand[np.argsort(-edge_w[cand])[: int(min(TOP_FO, cand.size))]]\n        neigh = np.unique(src[keep]).astype(int)\n        nstrength = np.bincount(src[keep], weights=edge_w[keep], minlength=int(graphs.n_nodes))\n        nsize = 90 + 230 * _norm01(nstrength[neigh])\n        ax.scatter(emb2[neigh, 0], emb2[neigh, 1], s=nsize, c=node_col, edgecolor="white", linewidth=0.5, alpha=0.95, zorder=4)\n        wn = _norm01(edge_w[keep])\n        for e, nn in zip(keep.tolist(), wn.tolist()):\n            _draw_arrow(ax, emb2[int(src[e])], emb2[int(dst[e])], color=edge_col, lw=1.5 + 3.4 * nn)\n        if PDF_SHOW_NODE_IDS:\n            for n in neigh[:8]:\n                ax.text(\n                    float(emb2[n, 0]),\n                    float(emb2[n, 1]),\n                    str(int(n)),\n                    fontsize=PDF_FONTSIZE_NODE_IDS,\n                    ha="center",\n                    va="center",\n                    zorder=9,\n                )\n        _panel_meta(ax, row)\n        return\n\n    if family in {"in2_mid", "in2_start", "out2_mid", "out2_end"}:\n        if family == "in2_mid":\n            cand = np.where((g2_v == node) & (group_arr[g2_m] == int(k)))[0]\n        elif family == "in2_start":\n            cand = np.where((g2_v == node) & (group_arr[g2_x] == int(k)))[0]\n        elif family == "out2_mid":\n            cand = np.where((g2_x == node) & (group_arr[g2_m] == int(k)))[0]\n        else:\n            cand = np.where((g2_x == node) & (group_arr[g2_v] == int(k)))[0]\n\n        if cand.size == 0:\n            _panel_meta(ax, row)\n            return\n\n        keep = cand[np.argsort(-g2w[cand])[: int(min(TOP_HO, cand.size))]]\n        wn = _norm01(g2w[keep])\n\n        if family in {"in2_mid", "in2_start"}:\n            core = np.unique(g2_m[keep]).astype(int)\n            side = np.unique(g2_x[keep]).astype(int)\n            side_col = "#d0d1e6"\n        else:\n            core = np.unique(g2_m[keep]).astype(int)\n            side = np.unique(g2_v[keep]).astype(int)\n            side_col = "#d0d1e6"\n\n        ax.scatter(emb2[side, 0], emb2[side, 1], s=75, c=side_col, edgecolor="white", linewidth=0.35, alpha=0.88, zorder=3)\n        ax.scatter(emb2[core, 0], emb2[core, 1], s=130, c=node_col, edgecolor="white", linewidth=0.45, alpha=0.96, zorder=4)\n\n        for ii, nn in zip(keep.tolist(), wn.tolist()):\n            x = int(g2_x[ii]); m = int(g2_m[ii]); v = int(g2_v[ii])\n            if family == "in2_mid":\n                _draw_arrow(ax, emb2[x], emb2[m], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=0.05)\n                _draw_arrow(ax, emb2[m], emb2[node], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=-0.05)\n            elif family == "in2_start":\n                _draw_arrow(ax, emb2[x], emb2[m], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=0.05)\n                _draw_arrow(ax, emb2[m], emb2[node], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=-0.05)\n            elif family == "out2_mid":\n                _draw_arrow(ax, emb2[node], emb2[m], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=0.05)\n                _draw_arrow(ax, emb2[m], emb2[v], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=-0.05)\n            else:\n                _draw_arrow(ax, emb2[node], emb2[m], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=0.05)\n                _draw_arrow(ax, emb2[m], emb2[v], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=-0.05)\n\n        if PDF_SHOW_NODE_IDS:\n            for n in core[:8]:\n                ax.text(\n                    float(emb2[n, 0]),\n                    float(emb2[n, 1]),\n                    str(int(n)),\n                    fontsize=PDF_FONTSIZE_NODE_IDS,\n                    ha="center",\n                    va="center",\n                    zorder=9,\n                )\n        _panel_meta(ax, row)\n        return\n\n    _panel_meta(ax, row)\n\n\ndef _draw_family_agg_panel(ax, row: dict, family: str, metric: str):\n    _base_panel(ax)\n    _panel_title(ax, row)\n    full_name = str(row.get("name", f"{family}_{metric}"))\n\n    if metric == "strength":\n        if family == "direct_in":\n            vals = _map_from_name(full_name, mode="sum", fallback_vals=fallback_direct_in_strength)\n            cmap = "YlOrRd"\n        elif family == "direct_out":\n            vals = _map_from_name(full_name, mode="sum", fallback_vals=fallback_direct_out_strength)\n            cmap = "YlGnBu"\n        elif family in {"in2_mid", "in2_start"}:\n            vals = _map_from_name(full_name, mode="sum", fallback_vals=fallback_in2_strength)\n            cmap = "Purples"\n        else:\n            vals = _map_from_name(full_name, mode="sum", fallback_vals=fallback_out2_strength)\n            cmap = "Greens"\n        size = 40 + 230 * _norm01(vals)\n    elif metric == "top1_mass":\n        vals = np.clip(_map_from_name(full_name, mode="mean", fallback_vals=np.zeros((graphs.n_nodes,), dtype=float)), 0.0, 1.0)\n        margin_name = full_name.replace("_top1_mass", "_top_margin")\n        margin_vals = np.clip(_map_from_name(margin_name, mode="mean", fallback_vals=np.zeros((graphs.n_nodes,), dtype=float)), 0.0, 1.0)\n        size = 40 + 240 * _norm01(margin_vals)\n        cmap = "viridis"\n    elif metric == "top_margin":\n        vals = np.clip(_map_from_name(full_name, mode="mean", fallback_vals=np.zeros((graphs.n_nodes,), dtype=float)), 0.0, 1.0)\n        size = 40 + 240 * _norm01(vals)\n        cmap = "magma"\n    else:\n        vals = _map_from_name(full_name, mode="mean", fallback_vals=np.zeros((graphs.n_nodes,), dtype=float))\n        size = 40 + 230 * _norm01(np.abs(vals))\n        cmap = "cividis"\n\n    ax.scatter(\n        emb2[:, 0],\n        emb2[:, 1],\n        c=vals,\n        s=size,\n        cmap=cmap,\n        alpha=0.92,\n        edgecolor="white",\n        linewidth=0.25,\n        zorder=4,\n    )\n\n    _panel_meta(ax, row)\n\n\ndef _draw_motif_panel(ax, row: dict, motif: str):\n    _base_panel(ax)\n    _panel_title(ax, row)\n    sign = 1.0 if float(row.get("contrib", 0.0)) >= 0.0 else -1.0\n    edge_col = "#d94801" if sign >= 0 else "#2171b5"\n    node_col = "#fdae6b" if sign >= 0 else "#9ecae1"\n\n    if motif == "fo_out_minus_in_log_strength":\n        vals = _map_from_name(\n            str(row.get("name", motif)),\n            mode="mean",\n            fallback_vals=np.log1p(fallback_direct_out_strength) - np.log1p(fallback_direct_in_strength),\n        )\n        size = 42 + 240 * _norm01(np.abs(vals))\n        ax.scatter(\n            emb2[:, 0],\n            emb2[:, 1],\n            c=vals,\n            s=size,\n            cmap="coolwarm",\n            alpha=0.92,\n            edgecolor="white",\n            linewidth=0.25,\n            zorder=4,\n        )\n        _panel_meta(ax, row)\n        return\n\n    if motif in {"ho_return_out_ratio", "ho_return_in_ratio"}:\n        cand = np.where((g2_x == node) & (g2_v == node))[0]\n        if cand.size == 0:\n            _panel_meta(ax, row)\n            return\n        keep = cand[np.argsort(-g2w[cand])[: int(min(TOP_HO, cand.size))]]\n        mids = np.unique(g2_m[keep]).astype(int)\n        m_strength = np.bincount(g2_m[keep], weights=g2w[keep], minlength=int(graphs.n_nodes))\n        m_size = 105 + 220 * _norm01(m_strength[mids])\n        ax.scatter(emb2[mids, 0], emb2[mids, 1], s=m_size, c=node_col, edgecolor="white", linewidth=0.5, alpha=0.95, zorder=4)\n        wn = _norm01(g2w[keep])\n        for ii, nn in zip(keep.tolist(), wn.tolist()):\n            m = int(g2_m[ii])\n            _draw_arrow(ax, emb2[node], emb2[m], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=0.10)\n            _draw_arrow(ax, emb2[m], emb2[node], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=-0.10)\n        if PDF_SHOW_NODE_IDS:\n            for n in mids[:8]:\n                ax.text(\n                    float(emb2[n, 0]),\n                    float(emb2[n, 1]),\n                    str(int(n)),\n                    fontsize=PDF_FONTSIZE_NODE_IDS,\n                    ha="center",\n                    va="center",\n                    zorder=9,\n                )\n        _panel_meta(ax, row)\n        return\n\n    if motif == "ho_bridge_out_ratio":\n        cand = np.where((g2_x == node) & (g2_m != node) & (g2_m != g2_v))[0]\n        if cand.size == 0:\n            _panel_meta(ax, row)\n            return\n        keep = cand[np.argsort(-g2w[cand])[: int(min(TOP_HO, cand.size))]]\n        mids = np.unique(g2_m[keep]).astype(int)\n        ends = np.unique(g2_v[keep]).astype(int)\n        ax.scatter(emb2[ends, 0], emb2[ends, 1], s=78, c="#d0d1e6", edgecolor="white", linewidth=0.35, alpha=0.88, zorder=3)\n        ax.scatter(emb2[mids, 0], emb2[mids, 1], s=130, c=node_col, edgecolor="white", linewidth=0.45, alpha=0.96, zorder=4)\n        wn = _norm01(g2w[keep])\n        for ii, nn in zip(keep.tolist(), wn.tolist()):\n            m = int(g2_m[ii]); v = int(g2_v[ii])\n            _draw_arrow(ax, emb2[node], emb2[m], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=0.05)\n            _draw_arrow(ax, emb2[m], emb2[v], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=-0.05)\n        _panel_meta(ax, row)\n        return\n\n    if motif == "ho_bridge_in_ratio":\n        cand = np.where((g2_v == node) & (g2_m != node) & (g2_m != g2_x))[0]\n        if cand.size == 0:\n            _panel_meta(ax, row)\n            return\n        keep = cand[np.argsort(-g2w[cand])[: int(min(TOP_HO, cand.size))]]\n        mids = np.unique(g2_m[keep]).astype(int)\n        src_nodes = np.unique(g2_x[keep]).astype(int)\n        ax.scatter(emb2[src_nodes, 0], emb2[src_nodes, 1], s=78, c="#d0d1e6", edgecolor="white", linewidth=0.35, alpha=0.88, zorder=3)\n        ax.scatter(emb2[mids, 0], emb2[mids, 1], s=130, c=node_col, edgecolor="white", linewidth=0.45, alpha=0.96, zorder=4)\n        wn = _norm01(g2w[keep])\n        for ii, nn in zip(keep.tolist(), wn.tolist()):\n            x = int(g2_x[ii]); m = int(g2_m[ii])\n            _draw_arrow(ax, emb2[x], emb2[m], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=0.05)\n            _draw_arrow(ax, emb2[m], emb2[node], color=edge_col, lw=1.2 + 2.8 * nn, linestyle="--", rad=-0.05)\n        _panel_meta(ax, row)\n        return\n\n    if motif in {"fo_reciprocity_out_ratio", "fo_reciprocity_in_ratio"}:\n        inc_out = np.where(src == node)[0]\n        inc_in = np.where(dst == node)[0]\n        in_neigh = set(src[inc_in].tolist())\n        out_neigh = set(dst[inc_out].tolist())\n        if motif == "fo_reciprocity_out_ratio":\n            cand = np.asarray([e for e in inc_out.tolist() if int(dst[e]) in in_neigh], dtype=int)\n        else:\n            cand = np.asarray([e for e in inc_in.tolist() if int(src[e]) in out_neigh], dtype=int)\n        if cand.size == 0:\n            _panel_meta(ax, row)\n            return\n        keep = cand[np.argsort(-edge_w[cand])[: int(min(TOP_FO, cand.size))]]\n        neigh = np.unique(np.concatenate([src[keep], dst[keep]])).astype(int)\n        neigh = neigh[neigh != int(node)]\n        n_strength = np.bincount(np.concatenate([src[keep], dst[keep]]), weights=np.concatenate([edge_w[keep], edge_w[keep]]), minlength=int(graphs.n_nodes))\n        n_size = 92 + 220 * _norm01(n_strength[neigh])\n        ax.scatter(emb2[neigh, 0], emb2[neigh, 1], s=n_size, c=node_col, edgecolor="white", linewidth=0.5, alpha=0.95, zorder=4)\n        wn = _norm01(edge_w[keep])\n        for e, nn in zip(keep.tolist(), wn.tolist()):\n            _draw_arrow(ax, emb2[int(src[e])], emb2[int(dst[e])], color=edge_col, lw=1.4 + 3.2 * nn)\n        _panel_meta(ax, row)\n        return\n\n    _panel_meta(ax, row)\n\n\nrows_pdf = _select_rows()\nif len(rows_pdf) == 0:\n    # Retry once with negative concepts enabled.\n    PDF_INCLUDE_NEGATIVE = True\n    rows_pdf = _select_rows()\n\nif len(rows_pdf) == 0:\n    # Last-resort fallback: top-|w*x| concepts for this node.\n    nz = np.where(np.isfinite(contrib_full))[0]\n    if nz.size > 0:\n        k_fb = max(1, int(PDF_MAX_PANELS))\n        top_idx = nz[np.argsort(-np.abs(contrib_full[nz]))[:k_fb]]\n        rows_pdf = [\n            {\n                "idx": int(j),\n                "name": str(concept_names[j]),\n                "label": _concept_label(str(concept_names[j])),\n                "contrib": float(contrib_full[j]),\n                "delta_p": np.nan,\n                "flip": 0,\n            }\n            for j in top_idx.tolist()\n        ]\n\nif len(rows_pdf) == 0:\n    raise RuntimeError("Compact panel fallback failed: no finite concept contributions for this node.")\n\nn_panels = min(len(rows_pdf), int(PDF_MAX_PANELS))\nn_cols = max(1, int(PDF_COLS))\nn_rows = int(math.ceil(float(n_panels) / float(n_cols)))\n\nfig, axs = plt.subplots(\n    n_rows,\n    n_cols,\n    figsize=(8.0 * n_cols, 6.0 * n_rows),\n    constrained_layout=True,\n)\naxs = np.atleast_1d(axs).reshape(-1)\n\nfor ax, row in zip(axs[:n_panels], rows_pdf[:n_panels]):\n    base = _base_name(str(row.get("name", "")))\n    fg = _parse_family_group(base)\n    if fg is not None:\n        fam, grp = fg\n        _draw_family_group_panel(ax, row, fam, int(grp))\n        continue\n\n    fa = _parse_family_agg(base)\n    if fa is not None:\n        fam, metric = fa\n        _draw_family_agg_panel(ax, row, fam, metric)\n        continue\n\n    motif = _parse_motif(base)\n    if motif is not None:\n        _draw_motif_panel(ax, row, motif)\n        continue\n\n    _base_panel(ax)\n    _panel_title(ax, row)\n    _panel_meta(ax, row)\n\nfor ax in axs[n_panels:]:\n    ax.axis("off")\n\nfig.suptitle(\n    f"Node {node} | pred class {pred_label} (p={pred_prob:.3f}) | compact concept evidence",\n    fontsize=PDF_FONTSIZE_SUPTITLE,\n)\n\nsaved_paths = []\nif SAVE_ADAPTIVE_PANELS_COMPACT:\n    safe_base = re.sub(r"[^A-Za-z0-9._-]+", "_", str(SAVE_ADAPTIVE_PANELS_COMPACT_BASENAME)).strip("_")\n    if len(safe_base) == 0:\n        safe_base = f"{_DATASET_TAG}_adaptive_panels_compact_node{node}"\n    if not safe_base.startswith(f"{_DATASET_TAG}_"):\n        safe_base = f"{_DATASET_TAG}_{safe_base}"\n\n    out_dir = Path(SAVE_ADAPTIVE_PANELS_COMPACT_DIR)\n    out_dir.mkdir(parents=True, exist_ok=True)\n\n    if SAVE_ADAPTIVE_PANELS_COMPACT_PDF:\n        out_pdf = out_dir / f"{safe_base}.pdf"\n        fig.savefig(out_pdf, dpi=int(PDF_DPI), bbox_inches="tight")\n        saved_paths.append(str(out_pdf.resolve()))\n    if SAVE_ADAPTIVE_PANELS_COMPACT_PNG:\n        out_png = out_dir / f"{safe_base}.png"\n        fig.savefig(out_png, dpi=int(PDF_DPI), bbox_inches="tight")\n        saved_paths.append(str(out_png.resolve()))\n\nplt.show()\n\nfor p in saved_paths:\n    print(f"[saved compact figure] {p}")\n\nprint(f"Compact adaptive panels for node {node}:")\nfor r in rows_pdf[:n_panels]:\n    print(\n        f"  - {r.get(\'label\', _base_name(r.get(\'name\', \'\')))} | "\n        f"w*x={float(r.get(\'contrib\', 0.0)):+.3f} | dP={_format_dp(r.get(\'delta_p\', np.nan))}"\n    )\n'

def run_adaptive_concept_maps_compact(ns: Dict[str, Any]) -> None:
    """Run former notebook cell 23."""
    _run(_CELL_23_CODE, ns)
